INSERT INTO ideas (id, titulo, notas, notas_internas, created_at, updated_at) VALUES ('1c054642-a902-4aaa-ad3c-6e3a7532853a'::uuid, '¿Qué piensan tus amigos?', '¿Qué piensan tus amigos cuando no estás delante? ¿No te preguntas eso?&nbsp;', 'Esto se me ocurre sobre todo para hacer una Grieta. ', '2026-05-04 08:45:47.455985+00'::timestamptz, '2026-05-04 17:45:30.717624+00'::timestamptz) ON CONFLICT (id) DO NOTHING;
INSERT INTO ideas (id, titulo, notas, notas_internas, created_at, updated_at) VALUES ('02faa4c0-d0eb-4974-9eb8-f5e3d2b7622a'::uuid, 'La Certeza como Activo', '', 'Esto sale de la entrevista que me hicieron Blanca y Javi sobre conversaciones sobre Dios. ', '2026-05-12 12:44:36.77542+00'::timestamptz, '2026-05-12 12:44:36.77542+00'::timestamptz) ON CONFLICT (id) DO NOTHING;
INSERT INTO ideas (id, titulo, notas, notas_internas, created_at, updated_at) VALUES ('aef30766-8df5-4912-866e-3516e08cc101'::uuid, 'Lifestyle Post Idea — “No confío en mi motivación”', 'No confío en mi motivación.<div>Por eso me mido.</div><div>Cada noche miro mi día y me hago preguntas que no siempre me apetece responder:</div><div>¿He cumplido mi palabra?<br>¿He cuidado mi cuerpo?<br>¿He avanzado en mi obra?<br>¿He tomado decisiones desde el centro o desde el miedo?<br>¿He vivido hoy como el hombre que digo que quiero ser?</div><div>No lo hago porque sea perfecto.<br>Lo hago porque sé perfectamente lo fácil que es mentirse.</div><div>Puedes tener una visión enorme, una marca potente, ideas brillantes, ambición real, incluso talento de sobra.</div><div>Y aun así perderte en el ruido.<br>En el móvil.<br>En la dispersión.<br>En la excusa elegante.<br>En el “mañana vuelvo”.</div><div>Por eso mi vida no se sostiene sobre inspiración.</div><div>Se sostiene sobre arquitectura.</div><div>Andorra, los proyectos, La Hermandad, el cuerpo, el dinero, la obra, la relación conmigo mismo… nada de eso se cuida solo.</div><div>Se cuida volviendo al marcador.<br>Volviendo a la palabra.<br>Volviendo a la pregunta incómoda:</div><div>¿Hoy he creado pruebas o solo he tenido buenas intenciones?</div><div>Ese es el lifestyle que quiero mostrar.</div><div>No coches.<br>No postureo.<br>No “mira qué libre soy”.</div><div>Sino algo mucho más raro:</div><div>un hombre intentando que su vida esté a la altura de su palabra.</div>', 'Esta idea ha salido trabajando dentro de Relevancy OS, el apartado de content. ', '2026-05-13 11:31:54.849176+00'::timestamptz, '2026-05-13 11:31:54.849176+00'::timestamptz) ON CONFLICT (id) DO NOTHING;
INSERT INTO ideas (id, titulo, notas, notas_internas, created_at, updated_at) VALUES ('efe94af0-ab18-4bce-a4de-24c401f94c35'::uuid, 'El lifestyle que te están vendiendo es Bali en bikini. El mío es Andorra a 5 grados.', '<div>Miro por la ventana: montaña. Niebla. Frío. Café fuerte. No hay influencer en la piscina ni luz dorada filtrada para Instagram. Solo un día por delante con su trabajo, su entrenamiento, su sesión con La Hermandad. Funcionalidad pura.<br>He vivido en Barcelona, Buenos Aires, Bogotá, Bali, Brasil y México. Conozco el sol eterno, el ruido y la audiencia que aplaude. En algún momento entendí que el confort climático permanente me estaba ablandando — necesitaba un sitio que me obligara a estar en mi cuerpo todos los días, sin negociación.<br>A eso vine a Andorra. Por eso me quedo.<br>Si tu lifestyle soñado todavía se parece al de un coach en hamaca, te están vendiendo el destino equivocado. La libertad real no es la playa permanente. Es elegir un entorno que te exija sostener quién dices que eres — todos los días, aunque haga frío.</div>', 'Esta idea ha salido trabajando dentro de Relevancy OS en el departamento de Content. ', '2026-05-13 11:32:22.124816+00'::timestamptz, '2026-05-13 11:32:22.124816+00'::timestamptz) ON CONFLICT (id) DO NOTHING;
INSERT INTO ideas (id, titulo, notas, notas_internas, created_at, updated_at) VALUES ('63d22c92-4b7f-477b-8636-790a518a7f4c'::uuid, 'Autoridad | Tu ansiedad no es un problema mental.', '"Tu ansiedad no es un problema de mente. Es un sistema nervioso pidiendo auxilio."<br>Aha: el avatar lleva años intentando "calmar la mente" sin tocar el cuerpo. Y por eso no le funciona. La paz mental no se construye desde la cabeza — empieza en el sueño, en el sistema nervioso, en la fuerza física.<br>Territorio / Pillar / Belief: Cuerpo como base + Pillar 5 + Belief 4<br>Por qué funciona: aha contraintuitivo brutal. La mayoría del avatar tiene ansiedad de fondo (21,5% del CSV literal) y está atascado en mindset coaching sin avanzar. Le abres un marco nuevo. Y es tu diferenciador biológico sin tocar antes en mails.', 'Esto es una idea de mail de autoridad, basada en el Relevancy OS, que me ha dado Claude en la conversación Relevancy OS. Como mail pero que se puede transformar en otro tipo de piezas, por supuesto. ', '2026-05-14 09:43:42.778086+00'::timestamptz, '2026-05-14 09:43:42.778086+00'::timestamptz) ON CONFLICT (id) DO NOTHING;
INSERT INTO ideas (id, titulo, notas, notas_internas, created_at, updated_at) VALUES ('3969c670-6c31-44fb-aedc-00d001b240bc'::uuid, 'Autoridad | No estás deprimido.', '<p>"No estás deprimido. Estás viviendo desconectado de tu estándar."<br>Aha: el avatar cree que tiene depresión cuando en realidad está viviendo por debajo de su fuego. Dos diagnósticos opuestos, dos curas distintas. Confundirlos te puede costar años.</p><p><br>Territorio / Pillar / Belief: Potencial no vivido + Pillar 1 + Belief 3<br>Por qué funciona: distinción quirúrgica. Le da al avatar lenguaje para nombrar lo que le pasa sin patologizarse. "Esto tiene un patrón. Tiene nombre." (Pain 1 del bloque cerrado.)</p><p><br>⚠️ Importante: este mail necesita cuidado redactando — debe ser explícito en que no minimiza la depresión clínica real. Es una distinción operativa, no un mensaje anti-salud-mental.</p>', 'Esto es una idea de mail de autoridad, basada en el Relevancy OS, que me ha dado Claude en la conversación Relevancy OS. Como mail pero que se puede transformar en otro tipo de piezas, por supuesto.', '2026-05-14 10:27:41.018067+00'::timestamptz, '2026-05-14 10:28:20.994146+00'::timestamptz) ON CONFLICT (id) DO NOTHING;
INSERT INTO ideas (id, titulo, notas, notas_internas, created_at, updated_at) VALUES ('ee292d95-a31b-4a54-bfc2-948b878809da'::uuid, 'Autoridad | ¿Por qué los creadores con más talento retrasan publicar?', '<p>"Por qué los creadores con más talento son los que más postergan publicar"<br>Aha: el talento alto y el bloqueo crónico son la misma moneda. El talento eleva el estándar interno; sin arquitectura para sostenerlo, ese estándar paraliza. No es vagancia. Es excelencia mal canalizada.</p><p><br>Territorio / Pillar / Belief: Psicología del creador ambicioso + Pillar 4 + Belief&nbsp;</p><p><br>Por qué funciona: ORO para tu avatar. Es el creador con obra parada que se siente vago cuando en realidad está atascado en su propia exigencia. Tu autoridad biográfica aquí es enorme (26 años trabajando con artistas de élite). Y es el territorio que menos creadores ocupan.</p>', 'Esto es una idea de mail de autoridad, basada en el Relevancy OS, que me ha dado Claude en la conversación Relevancy OS. Como mail pero que se puede transformar en otro tipo de piezas, por supuesto.', '2026-05-14 10:29:22.016862+00'::timestamptz, '2026-05-14 10:29:22.016862+00'::timestamptz) ON CONFLICT (id) DO NOTHING;
INSERT INTO ideas (id, titulo, notas, notas_internas, created_at, updated_at) VALUES ('b59784fc-38d8-40bc-8230-a76df309d239'::uuid, 'Autoridad | La disciplina no es el problema', '<p>"El día que entendí que la disciplina no era mi problema"<br>Aha: la disciplina no es lo que falta. Lo que falta es estructura que pida menos disciplina, no más. Si necesitas mucha fuerza de voluntad para sostener algo, el diseño está mal, no tú.</p><p><br>Territorio / Pillar / Belief: Motivación vs arquitectura + Pillar 3 + Belief 2</p><p><br>Por qué funciona: invierte el sentido común. Casi todo el contenido de desarrollo personal predica "más disciplina" y tú dices que pedir más disciplina al humano es derrota del diseño. Aha contraintuitivo + Pillar 3 (donde está la conversión).</p><p>Poner ejemplos claros como, por ejemplo, avanzar en los estudios con un sistema educativo que es una puta mierda. Coño, necesitas mucha fuerza de voluntad para sostener eso. Coño es que el diseño del sistema educativo está mal. No es que tú estés mal y esto se ha demostrado en sistemas educativos diferentes con los que no necesitas esa fuerza de voluntad desmedida.&nbsp;</p>', 'Esto es una idea de mail de autoridad, basada en el Relevancy OS, que me ha dado Claude en la conversación Relevancy OS. Como mail pero que se puede transformar en otro tipo de piezas, por supuesto.', '2026-05-14 10:30:46.358864+00'::timestamptz, '2026-05-14 10:30:46.358864+00'::timestamptz) ON CONFLICT (id) DO NOTHING;
INSERT INTO ideas (id, titulo, notas, notas_internas, created_at, updated_at) VALUES ('a0c60c48-5c9e-448e-b102-e7bed144aa14'::uuid, 'Autoridad | Lo que pasa después del Fénix', '<p>"Los tres primeros meses tras tocar fondo no son los más libres. Son los más peligrosos."</p><p><br>Aha: la cara B del mail Fénix. Después de la ceniza viene el rebote — y ese rebote, mal hecho, te lleva a la siguiente caída más rápido que si no hubieras caído nunca. La fase peligrosa no es romperse: es creer que ya estás bien.</p><p><br>Territorio / Pillar / Belief: Reconstrucción tras fondo + Pillar 1 + Belief 3</p><p><br>Por qué funciona: complementa El Fénix sin repetirlo. Le da al avatar el siguiente capítulo: "vale, me he convertido en ceniza, ya he ardido — ¿ahora qué?". Y abre tres errores concretos de esa fase. Conecta narrativamente con tu mail anterior.</p>', 'Esto es una idea de mail de autoridad, basada en el Relevancy OS, que me ha dado Claude en la conversación Relevancy OS. Como mail pero que se puede transformar en otro tipo de piezas, por supuesto.', '2026-05-14 10:31:44.679146+00'::timestamptz, '2026-05-14 10:31:44.679146+00'::timestamptz) ON CONFLICT (id) DO NOTHING;
INSERT INTO ideas (id, titulo, notas, notas_internas, created_at, updated_at) VALUES ('3f4866b8-0c05-4ae4-a6b7-7003a69bd242'::uuid, 'Autoridad | El desarrollo personal como entretenimiento espiritual', '<p>"El 95% del desarrollo personal es entretenimiento espiritual"</p><p><br>Aha: si lo que consumes no genera pruebas medibles en tu vida, es entretenimiento — por muy profundo que se sienta. La industria está diseñada para que te sientas mejor un rato sin que cambies nunca.</p><p><br>Territorio / Pillar / Belief: Soberanía frente a gurús + Belief 7 + Belief 6</p><p><br>Por qué funciona: el más polarizante de los ocho. Pierde tibios. Gana hermanos brutalmente leales. Y es Belief 7 sin tocar todavía en mails. Te separa del mercado entero en un solo correo. Riesgo: si la lista está en fase tibia, pierdes mucho. Si la lista ya tiene contexto Imperio, consolidas.</p>', 'Esto es una idea de mail de autoridad, basada en el Relevancy OS, que me ha dado Claude en la conversación Relevancy OS. Como mail pero que se puede transformar en otro tipo de piezas, por supuesto.', '2026-05-14 10:32:29.411797+00'::timestamptz, '2026-05-14 10:32:29.411797+00'::timestamptz) ON CONFLICT (id) DO NOTHING;
INSERT INTO ideas (id, titulo, notas, notas_internas, created_at, updated_at) VALUES ('28ea67e6-dd88-43c3-8595-0d1bfcc4ddd3'::uuid, 'Autoridad | La trampa del talento disperso', '<p>"La trampa del talento disperso: por qué tener muchas ideas no es ser creativo, es ser inejecutivo"</p><p><br>Aha: no es que tengas demasiadas ideas — es que ninguna te ha exigido convertirte en quien las ejecuta. La dispersión es un síntoma de identidad sin centro, no de creatividad alta. (20% del CSV: "tengo tantas ideas que no sé por dónde empezar".)</p><p><br>Territorio / Pillar / Belief: Brecha saber-hacer + Psicología del creador + Pillar 4 + Belief 1</p><p><br>Por qué funciona: pega directamente con un dolor verbalizado en los CSVs. Y reorganiza el marco del avatar (que cree que la dispersión es virtud creativa). Tu autoridad biográfica: has llevado seis proyectos / negocios / trayectorias y los has terminado.</p>', 'Esto es una idea de mail de autoridad, basada en el Relevancy OS, que me ha dado Claude en la conversación Relevancy OS. Como mail pero que se puede transformar en otro tipo de piezas, por supuesto.', '2026-05-14 10:33:12.646026+00'::timestamptz, '2026-05-14 10:33:12.646026+00'::timestamptz) ON CONFLICT (id) DO NOTHING;

-- piezas
INSERT INTO piezas (id, idea_id, titulo, formato, columna, contenido, fecha_publicacion, plataformas, url_publicacion, notas, kit_broadcast_id, instagram_media_id, tematica, last_synced_at, created_at, updated_at) VALUES ('38fb01a3-ee34-449f-bf67-bed9cd0ee734'::uuid, '8f565663-874b-48ec-8af8-d286a2f701d2'::uuid, 'Cuando Nadie te Ve', 'relampago', 'publicado', E'{"texto": "Llevas años haciéndote la pregunta equivocada.<div>\\"¿Quién soy?\\"</div><div>No.</div><div>¿Qué haces cuando estás cansado y nadie te mira?<br>¿Qué aguantas cuando aguantarlo no tiene testigos?<br>¿Qué traicionas cuando crees que nadie se entera?</div><div><b>Eso eres.</b></div><div>No lo que has descubierto en un puto test de personalidad.&nbsp;<br>No lo que proyectas en público cuando sabes que te miran.&nbsp;<br>No la versión de ti que aparece cuando el contexto te favorece.</div><div>Lo que haces en privado. Con coste real. Sin \\"audiencia\\".</div><div><b>Y si no te gusta lo que ves ahí… eso ya es algo.</b></div><div>Porque el momento en el que ya no puedes mirar para otro lado es Ignitio.</div><div>El fuego que no se puede desencender.</div><div>Guerra y honor ⚔️<br>Soma</div>"}'::jsonb, '2026-04-24 11:48:00+00'::timestamptz, '{Skool}'::text[], '', 'Se publica manualmente.', '', '', 'Identidad. Carácter. Privacidad. Ignitio.', NULL, '2026-04-15 19:23:50.177341+00'::timestamptz, '2026-04-24 17:24:07.965092+00'::timestamptz) ON CONFLICT (id) DO NOTHING;
INSERT INTO piezas (id, idea_id, titulo, formato, columna, contenido, fecha_publicacion, plataformas, url_publicacion, notas, kit_broadcast_id, instagram_media_id, tematica, last_synced_at, created_at, updated_at) VALUES ('2cff4c03-d2cf-42ef-ac57-dcbdbfe837f8'::uuid, 'a817e7cd-4fa1-4694-b728-65d2494d8024'::uuid, 'Muchos Hombres en Uno', 'relampago', 'publicado', E'{"texto": "<p></p><h2>Muchos Hombres en Uno | Relámpago ⚡️</h2><h2><span style=\\"color: rgb(192, 216, 192);\\"><br>Hay una frase que lo para todo.</span></h2><p></p><p>\\"Yo soy así.\\"</p><p>La dices y cierras una puerta. No sobre los demás. Sobre ti mismo.</p><p>Porque lo que estás haciendo realmente cuando la dices es esto: tomar una foto y llamarla película. <br>Confundir tu estado actual con tu naturaleza permanente. <br>Usar una historia sobre tu pasado para decretar lo que puede ser tu futuro.</p><p>Y esa historia, por muy coherente que te parezca, no es un registro fiel de lo que eres.</p><p>Es la versión con la que has sobrevivido.</p><p>Hay algo que las tradiciones más profundas llevan siglos diciéndonos y que tardamos en escuchar: no eres uno solo.</p><p><b>Eres muchos.</b></p><p>Y la mayoría de esos hombres ya han muerto mientras tú seguías vivo.</p><p>El que tenía ese miedo específico. <br>El que no podía sostener tal conversación. <br>El que necesitaba esa validación para moverse. <br>El que elegía la comodidad cada vez que el momento pedía algo más.</p><p><b>Ese ya no tiene por qué existir.</b></p><p>No porque lo hayas eliminado con voluntad pura, sino porque cruzar un Umbral real te cambia de forma irreversible.</p><p>El hombre que entra no es el que sale.<br>Y el que sale no puede fingir que sigue siendo el anterior.</p><p>Eso es lo que ocurre en el Ascenso.</p><p>No construyes encima de lo que eras. Mueres un poco.</p><p>Y lo que emerge después tiene una relación diferente con el miedo, con la acción y con lo que eres capaz de sostener en tu vida.</p><p>\\"Yo soy así\\" es la puta sentencia del que no ha cruzado nada todavía.<br>Del que sigue siendo el mismo hombre que entró.</p><p><b>Tú no tienes que serlo.</b></p><p>Guerra y honor ⚔️<br>Soma</p>"}'::jsonb, '2026-05-08 11:30:00+00'::timestamptz, '{Skool}'::text[], '', 'Se publica manualmente.', '', '', 'Identidad. Autoconocimiento. Introspección. Ascenso.', NULL, '2026-04-15 19:50:19.249275+00'::timestamptz, '2026-05-08 11:33:20.342262+00'::timestamptz) ON CONFLICT (id) DO NOTHING;
INSERT INTO piezas (id, idea_id, titulo, formato, columna, contenido, fecha_publicacion, plataformas, url_publicacion, notas, kit_broadcast_id, instagram_media_id, tematica, last_synced_at, created_at, updated_at) VALUES ('26bbfdb0-6647-486c-bce2-425ba2f0411f'::uuid, '98a6708c-dda7-407a-8d04-633300624d67'::uuid, 'No te Encuentras. Te forjas', 'relampago', 'agendado', '{"texto": "<h2>Deja de Buscarte | Relámpago ⚡️</h2><div><br></div><p>La búsqueda interminable parte de una idea equivocada.</p><p>Que hay algo que descubrir si excavas lo suficiente.&nbsp;</p><p>Una esencia pura que te espera detrás de las capas de condicionamiento que tienes.<br>Una respuesta que llegará si haces el retiro correcto, lees el libro correcto o te preguntas lo suficiente.</p><p>Ima no aparece en la excavación.</p><p><b>Aparece en la decisión difícil.&nbsp;</b></p><p>En el momento en el que podrías traicionarte y no lo haces. <br>En el coste real de mantenerte fiel a algo cuando te resultaría más fácil no hacerlo.</p><p>Ima siempre ha estado ahí.</p><p><b>Lo que no ha existido es una vida forjada a su altura.</b><br>Y esa vida no se descubre. Se forja.<br><br>En cada decisión que sostienes. <br>En cada Umbral que cruzas sin garantías. <br>En la consistencia pequeña, diaria e invisible que nadie aplaude… pero que Ima reconoce porque es desde donde habla.</p><p>Para eso existe La Hermandad.</p><p>No para que te encuentres.<br>Para que te forjes.</p><p>Guerra y honor ⚔️<br>Soma</p>"}'::jsonb, '2026-05-22 11:30:00+00'::timestamptz, '{Skool}'::text[], '', 'Se publica manualmente.', '', '', 'Autoconocimiento. Introspección. Forja. Ima.', NULL, '2026-04-15 19:53:13.666455+00'::timestamptz, '2026-04-19 18:43:57.303448+00'::timestamptz) ON CONFLICT (id) DO NOTHING;
INSERT INTO piezas (id, idea_id, titulo, formato, columna, contenido, fecha_publicacion, plataformas, url_publicacion, notas, kit_broadcast_id, instagram_media_id, tematica, last_synced_at, created_at, updated_at) VALUES ('a84b5143-e5c6-44ac-996f-5e62913f797f'::uuid, NULL, 'Storytelling | 2 yogures', 'email', 'publicado', '{"asunto": "Elena compró 2 yogures", "cuerpo": "Cuando murió su madre, Elena no lloró en el entierro.<div>Lloró 3 semanas después, un martes por la mañana, delante del armario de la cocina.</div><div>Porque había comprado 2 yogures.</div><div>Uno para ella. Otro para su madre. Por costumbre. Sin pensar.</div><div>Y ahí, con los 2 yogures en la mano, se dio cuenta de que el cuerpo tarda más que la cabeza en entender que alguien no vuelve.</div><div>El primer año fue raro de una forma que Elena nunca hubiera esperado.</div><div>No era solo la tristeza. Era la tristeza apareciendo en los sitios equivocados.</div><div>No en los momentos grandes. En los pequeños.</div><div>En la primera vez que hizo algo bueno y no pudo llamarla. En la primera vez que le dolió algo y no tuvo su voz.</div><div>En el silencio de los domingos por la tarde, que era cuando solían hablar y ahora tenían un peso distinto.</div><div>Un hueco con forma exacta.</div><div>Elena tardó mucho en entender que el dolor no era el problema.</div><div>Que el dolor era la medida.</div><div>Que dolía tanto porque había sido tanto. Que el tamaño de la pérdida era el tamaño de lo que había habido.</div><div>Y que intentar que doliera menos era, de alguna manera, pedirle a todo aquello que hubiera sido menos.</div><div>Y no quería eso.</div><div>No quería que hubiera sido menos.</div><div>Dejó la taza de su madre en el mismo sitio del armario.</div><div>No como un altar dramático.</div><div>Simplemente no la movió.</div><div>Y cada vez que la veía, en lugar de apartar los ojos, la miraba un momento.</div><div>Solo eso.</div><div>Un momento.</div><div>Y poco a poco ese momento dejó de doler igual.</div><div>No porque la echara menos de menos.</div><div>Sino porque había aprendido a estar en la misma habitación que la ausencia sin que la ausencia lo ocupara todo.</div><div>Hay personas que se quedan.</div><div>No en el sentido en el que nos gustaría. Ni de la manera que elegiríamos.</div><div>Se quedan en la manera en la que ves las cosas. En lo que te parece importante y en lo que no. En cómo tratas a la gente cuando estás cansado. En las cosas que defiendes aunque nadie más las defienda.</div><div>Se quedan ahí.</div><div>Silenciosas y permanentes. Sin necesitar que las invoques.</div><div>Elena sigue comprando yogures.</div><div>Ya solo uno.</div><div>Pero a veces, cuando abre el armario y ve la taza, sonríe.</div><div>No siempre. No todos los días.</div><div>Pero a veces.</div><div><b>Y ha entendido que eso no es olvidar.</b></div><div>Es exactamente lo contrario.</div><div>Es aprender a llevar a alguien contigo de una manera que no te rompe.</div><div>Que te acompaña.</div><div>Que está.</div><div>✨ Soma</div>", "preheader": "Cómo aprender a estar con lo que falta."}'::jsonb, '2026-04-20 11:30:00+00'::timestamptz, '{Kit}'::text[], '', '', '23659798', '', '', '2026-05-14 10:13:02.778+00'::timestamptz, '2026-04-15 21:06:19.010746+00'::timestamptz, '2026-05-14 10:13:02.795471+00'::timestamptz) ON CONFLICT (id) DO NOTHING;
INSERT INTO piezas (id, idea_id, titulo, formato, columna, contenido, fecha_publicacion, plataformas, url_publicacion, notas, kit_broadcast_id, instagram_media_id, tematica, last_synced_at, created_at, updated_at) VALUES ('06c66568-58ee-4ad3-a16e-8ebf037b1360'::uuid, 'c5952edb-6a19-4f42-9dfe-e943698075af'::uuid, 'El Problema de Escuchar tu Alma', 'youtube', 'desarrollo', E'{"guion": "<div>GUION: \\"El Problema de Escuchar Tu Alma\\"</div><div>[GANCHO VISUAL]<br>Soma a cámara. Sin intro. Sin música. Silencio de un segundo. Expresión seria, sin sonrisa.</div><div>[GANCHO HABLADO] (0-10s)<br>Tu vida tiene que funcionar como una secta.<br>(pausa de 2 segundos)<br>Y sé que esa frase te revuelve algo por dentro. Bien. Significa que lo que viene te va a costar escuchar.</div><div>[CONFIRMACIÓN DEL CLIC] (10-40s)<br>Hoy voy a hablarte de la parte del desarrollo personal y espiritual que nadie tiene motivos para enseñarte.<br>No porque sea un secreto. Sino porque no vende.<br>Y cuando termines este video vas a entender por qué llevas años escuchándote a ti mismo… y sin embargo tu vida sigue sin reflejar lo que la voz de tu alma te dice.</div><div>[EL CONSENSO — setup] (35s-1:30)<br>Mira, hay algo que es verdad.<br>Escuchar tu voz interior es un trabajo real. Es difícil. La mayoría de la gente pasa la vida entera sin hacerlo en serio. Tapada de ruido, de agenda, de lo que se supone que tiene que ser.<br>Y cuando alguien por fin lo consigue… cuando por fin hay un momento de silencio real y la voz aparece… eso es genuino. Eso es poderoso. Eso cambia algo.<br>No estoy aquí para quitarte eso. Ni para criticar el trabajo interno, ni para atacar la espiritualidad. No estoy aquí para decirte que escucharte a ti mismo no sirve, porque sí sirve.&nbsp;<br>Estoy aquí para decirte que eso solo es la primera mitad de la ecuación. Y que creerte que la primera mitad es toda la película es exactamente la trampa en la que más gente cae.</div><div>[POR QUÉ UNA SECTA — el argumento completo] (40s-3:00)<br>Las sectas tienen muy mala fama. Merecida.<br>Pero antes de que tu cerebro las descarte por completo, escucha esto.<br>Las sectas funcionan. Y funcionan por razones muy concretas.<br>Una secta reduce la incertidumbre de sus miembros. En un mundo donde nadie sabe muy bien qué está haciendo, dónde va ni por qué las cosas son como son… una secta llega y dice: aquí tienes las reglas. Aquí tienes el camino. Aquí tienes la respuesta.<br>Y eso, aunque suene peligroso, cubre una necesidad humana real.<br>Una secta ofrece liderazgo, te da un conjunto de normas claras cuando el resto del mundo te ofrece solo ambigüedad. El líder nos marca un norte cuando la mayoría está girando en círculos.<br>Eso no es malo. Eso es poderoso.<br>El problema de las sectas no es la estructura. Es que alguien de fuera te controla dentro de esa estructura. El líder usa la claridad que te da para aprovecharse de ti. Para mantenerte dependiente. Para quedarse con tu dinero, tu tiempo o tu criterio. Es decir, juegan en tu contra, no a tu favor.<br>Ahí está el problema. No en el modelo. En quién lo opera.<br>Y por eso nuestra vida tiene que funcionar como una secta.<br>Porque necesitamos la estructura. Necesitamos las reglas claras. Necesitamos el camino definido.<br>Pero el que opera esa secta tienes que ser tú.</div><div>[RE-HOOK 1] (~3:00)<br>Y aquí está el problema. Porque hay dos roles en cualquier secta. Y solo te han enseñado uno.</div><div>[LOS DOS ROLES — la metáfora completa] (3:00-6:30)<br>Toda secta tiene un líder y un seguidor.<br>El líder es quien habla. Quien define las normas. Quien dice qué es verdad y qué no.<br>El seguidor es quien obedece. Quien ejecuta. Quien hace lo que el líder dice aunque no le apetezca, aunque duela, aunque implique sacrificio.<br>En la secta de tu vida, el líder es tu voz más profunda. La voz que aparece en el silencio. Que no discute. Que no negocia. Que simplemente señala.<br>Y el seguidor eres tú también.<br>El problema es que el mercado lleva décadas vendiéndote solo el primer rol.<br>Escucha al líder. Conecta con tu voz interior. Aprende a distinguir lo que realmente quieres de lo que te han dicho que quieres. Medita. Reflexiona. Terapia. Retiro. Otro libro. Otro curso.<br>Toda una puta industria construida alrededor de ayudarte a escuchar al líder.<br>Y el seguidor… el seguidor no existe en ese mercado.<br>Porque el seguidor no genera sensaciones bonitas. El seguidor no produce el estado de plenitud de \\"ya me conozco a mí mismo\\". El seguidor no tiene retiros de fin de semana.<br>El seguidor tiene que dejar ese trabajo.<br>El seguidor tiene que tener esa conversación que lleva meses evitando.<br>El seguidor tiene que lanzar algo sin saber si va a funcionar.<br>El seguidor tiene que cerrar una puerta que todavía no sabe si quiere cerrar.</div><div>[EL ESPEJISMO] (4:00-6:00)<br>Y aquí está la trampa.<br>Cuando por fin conectas con esa voz, cuando por fin el líder que vive dentro de ti habla con claridad… hay un momento de plenitud enorme. De alegría. De \\"ya lo tengo\\". Como si algo que llevaba mucho tiempo buscando por fin hubiera aparecido.<br>Eso es real. No es ilusión.<br>Pero es un espejismo si te quedas ahí.<br>Porque esa sensación, ese gustito mental y emocional de \\"ya me escucho a mí mismo, ya sé lo que quiero, ya sé quién soy\\"… no es el destino. Es el punto de salida.<br>El problema es que se siente tan bien que la gente se queda viviendo ahí.<br>Comprando otro libro sobre cómo profundizar en esa conexión. Haciendo otro retiro. Otro curso de meditación. Otra terapia que les ayude a entender mejor lo que la voz les dice.<br>Y la voz lleva meses diciéndoles lo mismo.<br>La voz no necesita que la entiendas mejor. Necesita que le obedezcas. Como hace un buen seguidor en una secta.</div><div>[RE-HOOK 2] (~6:30)<br>Y ahora viene la parte que nadie del sector quiere que veas. Porque el problema no solo está fuera.</div><div>[EL ENEMIGO — concreto, en dos caras] (6:30-9:30)<br>El enemigo aquí tiene dos caras. Y si solo ves la primera, te pierdes la que más importa.<br>La primera cara es externa. Y es fácil de señalar.<br>Es el mercado espiritual que lleva décadas diciéndote que la respuesta está dentro de ti. Y tiene razón. Pero te vende solo la mitad del trabajo.<br>Es el gurú que te lleva a un retiro de silencio de diez días donde conectas con algo profundo y real… y luego vuelves a casa y en dos semanas estás igual que antes. Y entonces piensas que necesitas otro retiro.<br>Es la industria del \\"todo fluye\\", del \\"el universo conspira\\", del \\"confía en el proceso\\". Frases que tienen una parte de verdad pero que se han convertido en el mejor escudo para no tomar decisiones reales.<br>Es el mundo de la introspección infinita. Gente que lleva años explorándose, entendiéndose, comprendiéndose… y cuya vida exterior no ha cambiado nada en ese mismo período.<br>Esa es la primera cara.<br>Pero la segunda cara eres tú.<br>Y esta es la que duele.<br>Eres tú cuando sabes que esa relación está muerta.<br>No hoy. Llevas tiempo sabiéndolo. Tu voz lo dice con una claridad que te molesta porque no puedes ignorarla. Y sin embargo sigues ahí. Porque salir tiene un coste real. Porque hay historia, o hay miedo a la soledad, o hay hijos, o hay una hipoteca.<br>Y cada noche que te acuestas con esa verdad sin moverte… es un día más siendo el peor seguidor de ti mismo. Es un día más de traición a tu propio y más sabio liderazgo.<br>Eres tú cuando sabes exactamente qué emprendimiento tienes que lanzar o qué cambio tienes que hacer en el que ya tienes.<br>No es una intuición vaga. Es una certeza. Y llevas meses sin moverla. No porque no tengas tiempo. Porque si lo lanzas y fracasa ya no puedes vivir de la posibilidad. Ya no puedes seguir diciéndote que \\"cuando lo hagas bien, funcionará”.<br>Y la posibilidad, aunque no sea nada, es más cómoda que el riesgo de la realidad.<br>Eres tú cuando sabes que estás cobrando menos de lo que vales.<br>Y sabes qué tendrías que cambiar para que eso dejara de ser así. Pero cambiarlo significa tener conversaciones que no quieres tener, cerrar clientes que no te convienen, entrar en un mercado donde empiezas de cero.<br>En todos estos casos tu voz ha hablado.<br>Con claridad. Con fuerza.<br>Y tú la has escuchado.<br>Y no has hecho nada para moverte.<br>Porque moverse da terror.<br>Eso no es un problema de conexión interior. Eso es un problema de obediencia.</div><div>[EL ENEMIGO NOMBRADO] (8:30-10:00)<br>El problema no es que el mercado del desarrollo personal y la espiritualidad mienta.<br>El problema es que vende media verdad. Y media verdad es más peligrosa que una mentira entera porque tiene la suficiente parte real para que te la creas.<br>La primera mitad de la ecuación, escucharte, tiene un mercado enorme. Millones de libros. Miles de cursos. Cientos de retiros. Toda una industria construida alrededor de ayudarte a conectar con tu voz interior.<br>La segunda mitad no tiene mercado porque no vende igual de bien.<br>¿Sabes por qué?<br>Porque la segunda mitad duele. Porque la segunda mitad no te hace sentir bien. Porque la segunda mitad implica cerrar puentes, perder seguridad, tomar decisiones que el entorno no va a validar.<br>Porque te exige que obedezcas.<br>Un gurú que te ayuda a escucharte a ti mismo puede prometerte paz interior.<br>Un sistema que te exige ejecutar lo que la voz de tu alma dice solo puede prometerte una cosa: que va a ser más difícil que quedarte donde estás.<br>¿Cuál crees que vende más?</div><div>[HISTORIA PERSONAL DE SOMA] (10:00-11:30)<br>[Aquí va el momento concreto de Soma: la vez que su voz le dijo algo específico que no quería obedecer, el período en que se quedó en \\"el gustito\\" sin ejecutar, y el punto de inflexión. La estructura es: el dolor de la situación → lo que la voz decía → cuánto tiempo tardó en obedecer → qué pasó cuando lo hizo. Real, específico, sin suavizar el coste.]</div><div>[RE-HOOK 4] (~12:30)<br>Ahora bien. La pregunta que queda en el aire y que nadie responde es esta: ¿cómo sé si estoy ejecutando, como sé si estoy siguiendo mi propio liderazgo o si solo me estoy contando que ejecuto?</div><div>[LA RESPUESTA: LA CRUZ CARDINAL] (12:30-14:00)<br>El problema de \\"obedece a tu voz interior\\" es que es tan abstracto que puedes convencerte de que lo estás haciendo cuando no estás moviendo nada.<br>Puedes convencerte de que \\"estás en proceso\\" durante años.<br>Puedes tener un discurso completamente coherente de por qué todavía no es el momento y seguir sin hacer nada.<br>Lo que diferencia a un Indomable de alguien que vive de la espiritualidad sin encarnación es que el Indomable tiene un sistema de medición.<br>No para controlarse. Sino para no mentirse.<br>En Imperio Indomable trabajamos con algo que llamamos La Cruz Cardinal. Ocho acciones concretas que se miden cada día. No como lista de tareas. Como espejo objetivo que muestra la distancia entre lo que tu voz dice y lo que tu vida demuestra.<br>¿Lo que dice tu voz interior sobre tu cuerpo se está manifestando en lo que comes, en cómo duermes, en cómo te mueves? ¿O solo en lo que piensas sobre el tema?<br>¿Lo que dice sobre tu negocio se está manifestando en conversaciones reales, en ofertas reales, en decisiones reales? ¿O solo en tu cabeza?<br>¿Lo que dice tu voz interior sobre tu negocio se está manifestando en las conversaciones que tienes, en las ofertas que haces, en las puertas que cierras? ¿O solo en tus ideas sobre cómo debería ser?<br>¿Lo que dice sobre tus relaciones se está manifestando en cómo hablas, en qué toleras, en qué exiges? ¿O solo en tu discurso interno de lo que te mereces?<br>Los datos no mienten. La historia que te cuentas sobre ti mismo sí puede mentir.<br>La Cruz Cardinal no te dice lo que tienes que hacer. Te muestra lo que realmente estás haciendo. Y esa brecha, entre lo que tu voz dice y lo que tu vida demuestra, es el único indicador que importa.</div><div>[CIERRE] (14:00-14:45)<br>Escuchar tu voz interior es la parte noble del camino.<br>Obedecerla cuando te dice algo que da terror… eso es otra historia.<br>Hay dos tipos de personas que conectan con su voz más profunda.<br>Las que se quedan viviendo en la sensación de haberlo conseguido.<br>Y las que se levantan, sienten el miedo de lo que su voz interior les pide… y obeceden de todas formas.<br>Tu alma habla.<br>Tu vida demuestra si le haces caso.<br>Si quieres dejar de quedarte en la primera mitad, lo que hacemos dentro de La Hermandad va mucho más lejos que escucharte. Te exige obedecerte. Con datos. Con estructura. Con Hermanos que van a ver si lo que dices que vas a hacer ocurre o no.<br>El link está en la descripción.<br>Guerra y honor ⚔️</div><div>NOTAS DE PRODUCCIÓN<br>Frase nuclear del video (para thumbnail y título): \\"Tu alma habla. Tu vida demuestra si le haces caso.\\"<br><br>Opciones de título:<br>&nbsp;•\\t\\"El problema de escuchar tu alma\\" (neutro, directo)<br>&nbsp;•\\t\\"Por qué escucharte a ti mismo no es suficiente\\"<br>&nbsp;•\\t\\"La mitad que el desarrollo personal no te enseña\\"<br>&nbsp;•\\t\\"Escuchar tu voz interior no sirve de nada\\" (más agresivo, mayor CTR, más riesgo)<br>&nbsp;•\\t\\"Por qué escucharte a ti mismo no es suficiente\\" (marco negativo, más CTR)<br>&nbsp;•\\t\\"Tu vida tiene que funcionar como una secta\\" (el más provocador, mayor riesgo, mayor recompensa)</div><div>Thumbnail: Soma a cámara, expresión seria. Texto grande en pantalla: \\"Tu alma habla.\\" Segunda línea en color contrastado: \\"¿Y tú?\\" Fondo oscuro — testear contraste para Dark Mode.</div>", "descripcion": "", "titulo_video": "Escuchar tu voz interior no sirve de nada"}'::jsonb, '2026-04-24 18:28:00+00'::timestamptz, '{YouTube}'::text[], '', '', '', '', '', NULL, '2026-04-18 15:34:52.398857+00'::timestamptz, '2026-04-22 21:19:57.751019+00'::timestamptz) ON CONFLICT (id) DO NOTHING;
INSERT INTO piezas (id, idea_id, titulo, formato, columna, contenido, fecha_publicacion, plataformas, url_publicacion, notas, kit_broadcast_id, instagram_media_id, tematica, last_synced_at, created_at, updated_at) VALUES ('75ba6037-b77a-4c6c-9064-6be9bce41ea4'::uuid, NULL, 'Storytelling | El Perdón', 'email', 'publicado', E'{"asunto": "Estás pagando una deuda que no es tuya", "cuerpo": "Andrés llevaba 8 años enfadado con su padre.<div>Era un enfado silencioso, de los que se instalan en el fondo y desde ahí lo tiñen todo.</div><div>Lo notaba en que había cosas que no hacía, decisiones que no tomaba y versiones de sí mismo que no se permitía, porque de alguna manera todo eso estaba conectado con él.</div><div>Con lo que le había hecho. Con lo que no le había dado. Con lo que tendría que haber sido y no fue.</div><div>No vamos a decir qué pasó.</div><div>Porque lo que pasó no importa tanto como lo que Andrés hizo con ello.</div><div>Y lo que Andrés hizo fue cargarlo.</div><div>8 putos años dedicando energía y espacio interior a mantener vivo algo que ya había pasado.</div><div>Como remar contra una corriente que no para, con los brazos siempre en tensión. Sin poder soltar los remos porque si los sueltas la corriente te lleva y eso parece peor.</div><div>Pero los remos no te llevan a ningún sitio.</div><div>Solo te mantienen quieto.</div><div>Agotado y quieto.</div><div>Un día Andrés se dio cuenta de algo.</div><div>Que el enfado no le hacía daño a su padre.</div><div>Su padre dormía y comía. Su padre follaba y tenía sus días y su vida y su manera de ver las cosas que no incluía saber el peso exacto que Andrés llevaba encima.</div><div>El enfado solo vivía en un sitio.</div><div>Dentro de Andrés.</div><div>Y eso lo cambió todo.</div><div>No de golpe, claro. Porque las cosas reales no cambian de golpe.</div><div>Pero algo se movió.</div><div>Andrés había confundido perdonar con decir que estaba bien.</div><div>Que lo que pasó no había pasado. Que no importaba. Que el otro tenía razón.</div><div>Y eso no podía hacerlo. Porque no era verdad.</div><div>Había pasado. Importaba. Y el otro no tenía razón.</div><div>Pero perdonar no era eso.</div><div>Perdonar era soltar los remos.</div><div>Para dejar de gastar la energía que necesitaba para construir algo en el presente en mantener vivo algo del pasado.</div><div>No llamó a su padre.</div><div>No hubo conversación. No hubo momento cine.</div><div>Simplemente un día Andrés decidió que ya no iba a seguir organizando su vida alrededor de una herida.</div><div>Que había sido real y le había costado lo que le había costado. Y que precisamente por eso no merecía seguir costándole más.</div><div>Ya había pagado suficiente por algo que no había sido culpa suya.</div><div>Lo que nadie te cuenta del perdón es lo que aparece cuando sueltas.</div><div>Andrés empezó a tener energía para cosas para las que antes no tenía.</div><div>No porque hubiera descansado, sino porque había dejado de gastar en algo que no le devolvía nada.</div><div>Empezó a tomar decisiones que antes no tomaba y a permitirse cosas que antes no se permitía. A construir sin mirar todo el rato hacia atrás para comprobar que el enfado seguía ahí.</div><div>El enfado seguía. Pero cada vez más pequeño.</div><div>Como pasa con las cosas a las que dejas de alimentar.</div><div>Hay alguien en tu vida que te debe algo que seguramente no te va a pagar.</div><div>Una disculpa. Un reconocimiento. Una conversación que tendría que haber pasado y no ha pasado.</div><div>Y llevas tiempo esperando ese pago para poder seguir.</div><div>Pero el pago no llega. Y tú sigues parado.</div><div>Esperando una deuda que el otro ni sabe que tiene.</div><div>El perdón no es decir que \\"x cosa\\" estuvo bien.</div><div>El perdón es decidir que ya no vas a seguir pagando tú una deuda que es de otro.</div><div>Es soltar los remos.</div><div>No por él.</div><div>Por ti.</div><div>Para que los brazos que llevan años remando contra la corriente puedan por fin empezar a construir algo.</div><div>Lo que tendrías que haber construido hace tiempo.</div><div>Lo que todavía puedes construir.</div><div>Empieza hoy.</div><div>🌊 Soma</div>", "preheader": "El otro ya siguió con su vida. Tú no."}'::jsonb, '2026-04-27 11:30:30+00'::timestamptz, '{Kit}'::text[], '', '', '23659903', '', '', '2026-05-14 10:13:02.357+00'::timestamptz, '2026-04-19 17:22:53.692247+00'::timestamptz, '2026-05-14 10:13:02.372018+00'::timestamptz) ON CONFLICT (id) DO NOTHING;
INSERT INTO piezas (id, idea_id, titulo, formato, columna, contenido, fecha_publicacion, plataformas, url_publicacion, notas, kit_broadcast_id, instagram_media_id, tematica, last_synced_at, created_at, updated_at) VALUES ('b28de007-c30b-454e-97d7-22bb30bd3d35'::uuid, NULL, 'Storytelling | La vida correcta', 'email', 'publicado', '{"asunto": "Carlos no es infeliz. Pero tampoco está vivo", "cuerpo": "Carlos tenía todo lo que se supone que hay que tener.<div>Casa. Coche. Trabajo estable. Familia.</div><div>Había seguido los pasos en el orden correcto y había llegado a los sitios que se llegaba cuando seguías los pasos en el orden correcto.</div><div>Y a los 46 años, sentado en el sofá un miércoles por la tarde, se dio cuenta de que llevaba 20 años muriéndose despacio.</div><div>No era infeliz.</div><div>Eso era lo más difícil de explicar.</div><div>Carlos no tenía motivos para quejarse. Tenía cosas que mucha gente no tenía.</div><div>Pero había algo que le faltaba y que siempre le había faltado y que había aprendido a no mirar de frente porque mirarlo de frente era demasiado incómodo.</div><div>Que nunca había elegido nada.</div><div>Que había aceptado todo, joder.</div><div>El trabajo porque era seguro. La ciudad porque era donde estaba. La vida porque era la que había llegado.</div><div>Nunca había dicho sí a algo con el cuerpo entero. Nunca había dicho no a algo que no quería de verdad.</div><div>Había dejado que la corriente lo llevara.</div><div>Y la corriente lo había llevado a un sitio perfectamente razonable.</div><div>Perfectamente vacío.</div><div>Lo más duro no era eso.</div><div>Era que en muchos momentos a lo largo de esos 20 años, algo dentro de él había levantado la mano.</div><div>Una idea. Un impulso. Una voz muy baja que decía esto no, esto no es.</div><div>Y Carlos había aprendido a apagarla tan bien que ya casi no la escuchaba.</div><div>La había apagado con la comodidad. Con la hipoteca. Con el qué dirán. Con el ya lo haré cuando. Con el no es el momento. Con el soy demasiado mayor. Con el tengo demasiadas responsabilidades.</div><div>Con todo el arsenal de razones razonables que los seres humanos usamos para no vivir la vida que queremos vivir.</div><div>Carlos no era cobarde en el sentido clásico.</div><div>En una emergencia habría dado la cara. Por su familia habría hecho cualquier cosa.</div><div>Pero le había faltado un tipo específico de valentía.</div><div>El más difícil.</div><div>La valentía de decirle a tu propia vida que no te basta. Que quieres más. Que mereces más. Que la versión correcta y razonable y aprobada por todos de ti mismo no es suficiente.</div><div>Esa valentía no hace ruido. Ni tiene público aplaudiendo.</div><div>Es la más solitaria de todas. Y por eso es la que más cuesta.</div><div>Carlos se quedó sentado en el sofá un rato largo con la tele encendida sin sonido.</div><div>Y pensó algo que no se había permitido pensar nunca con esa claridad.</div><div>Que todavía no estaba muerto.</div><div>Que 46 años no era el final. Que había personas que habían empezado a los 50. A los 55. Que habían tirado 20 años de vida correcta por la ventana y habían construido algo real con lo que les quedaba.</div><div>No sin miedo. Sin miedo no.</div><div>Pero con miedo y de todas formas.</div><div>Esta historia no tiene final todavía.</div><div>Porque Carlos eres tú.</div><div>O es la versión de ti que sabe que hay algo apagado y que lleva tiempo sin mirarlo de frente porque mirarlo de frente obliga a hacer algo con ello.</div><div>Y hacer algo con ello acojona.</div><div>Porque significa renunciar a la comodidad de la vida correcta. Significa decepcionar a alguien. Significa no tener garantías. Significa empezar sin saber si vas a llegar.</div><div>Pero aquí está la verdad que nadie dice en voz alta:</div><div>La vida correcta también tiene un coste.</div><div>No lo parece porque es un coste silencioso, repartido en pequeñas dosis diarias, imposible de ver en un solo día pero devastador visto desde el sofá de los 46 años.</div><div>El coste de no haber elegido. De no haber intentado. De haber apagado la voz tantas veces que ya casi no habla.</div><div>Ese coste lo pagas igual.</div><div>La única diferencia es que si lo pagas por haber intentado, tienes algo a cambio.</div><div>Si lo pagas por no haber intentado, no tienes nada.</div><div>No es demasiado tarde.</div><div>Pero el momento de empezar no es cuando desaparece el miedo.</div><div>El miedo no desaparece.</div><div>El momento de empezar es ahora. Con el miedo dentro. Con las dudas dentro. Con todas las razones razonables para no hacerlo dentro.</div><div>Y de todas formas.</div><div>✊🏼 Soma</div><div>​</div>", "preheader": "Porque no le duele lo suficiente como para cambiar."}'::jsonb, '2026-05-04 12:57:26+00'::timestamptz, '{Kit}'::text[], '', '', '23660043', '', '', '2026-05-14 10:13:02.157+00'::timestamptz, '2026-04-19 17:26:15.257383+00'::timestamptz, '2026-05-14 10:13:02.172801+00'::timestamptz) ON CONFLICT (id) DO NOTHING;
INSERT INTO piezas (id, idea_id, titulo, formato, columna, contenido, fecha_publicacion, plataformas, url_publicacion, notas, kit_broadcast_id, instagram_media_id, tematica, last_synced_at, created_at, updated_at) VALUES ('f3642f3a-2209-460f-9107-1b17eb8c15a7'::uuid, NULL, 'Storytelling | El honor', 'email', 'publicado', '{"asunto": "El honor está en la batalla", "cuerpo": "Ana tenía 42 años cuando plantó su primer olivo.<div>No tenía tierra propia todavía. Lo plantó en un tiesto grande en la terraza del piso donde vivía de alquiler.</div><div>Su vecino le dijo que los olivos tardaban años en dar fruto. Que igual no llegaba a verlo.</div><div>Ana le dijo que lo sabía. Y lo plantó de todas formas.</div><div>Llevaba 3 años intentando dejar la ciudad.</div><div>No porque fuera un mal sitio. Sino porque había algo que la llamaba desde mucho antes y que ella había ido posponiendo con el silencio con el que posponemos las cosas que nos importan de verdad.</div><div>Un trozo de tierra. Una casa pequeña. Un ritmo que fuera suyo.</div><div>No lo había contado mucho.</div><div>Las cosas grandes a veces es mejor no contarlas hasta que están lo suficientemente arraigadas como para aguantar el peso de las opiniones de los demás.</div><div>Hubo obstáculos. Claro.</div><div>El dinero que no llegaba cuando tenía que llegar. El terreno que se cayó en el último momento. El año en que tuvo que volver a empezar desde un punto más atrás del que había empezado antes.</div><div>Ana no lo vivió como señales de que no debía seguir.</div><div>Lo vivió como el camino.</div><div>Porque había entendido algo que cambió la manera en que se movía por todo aquello.</div><div>Que el honor no estaba en llegar.</div><div>Estaba en no parar.</div><div>Había mañanas difíciles en las que los números no cuadraban y la duda llegaba con toda su lógica y sus argumentos razonables.</div><div>En esas mañanas Ana salía a la terraza y miraba el olivo.</div><div>Que había crecido despacio, como crecen los olivos, sin necesitar que nadie le confirmara que iba bien.</div><div>Y algo en esa imagen le devolvía algo.</div><div>No la fe de que iba a llegar.</div><div>La fe de que valía la pena seguir intentándolo.</div><div>Y que eso era suficiente por hoy.</div><div>Lo que Ana había descubierto es que perseguir algo real te cambia por dentro independientemente del resultado.</div><div>Que el que lucha por algo que ha elegido de verdad desarrolla una relación consigo mismo que no se compra y no se aprende en ningún otro sitio.</div><div>Una confianza que no viene de haber ganado.</div><div>Viene de haberse visto en las mañanas difíciles. De haberse visto dudar y seguir. De haberse visto caer y levantarse sin hacer mucho ruido.</div><div>De saber, con el cuerpo entero, que cuando las cosas se ponen difíciles tú eres de los que no sueltan.</div><div>Eso no te lo quita nadie.</div><div>Ni el resultado. Ni el tiempo. Ni nadie.</div><div>Hace 3 meses Ana firmó.</div><div>Un terreno pequeño con una casa que necesita trabajo y 2 olivos ya plantados que llevan ahí más años que ella.</div><div>No era exactamente lo que había imaginado al principio.</div><div>Era mejor.</div><div>Porque era real y era suyo y tenía las marcas exactas de todo lo que le había costado llegar hasta ahí.</div><div>No te estoy contando esto para decirte que si luchas suficiente consigues lo que quieres.</div><div>A veces sí. A veces no. A veces llegas a algo distinto que resulta ser mejor.</div><div>Te lo cuento porque hay una versión de ti que sabe lo que quiere.</div><div>Que lo sabe con tranquilidad, cuando no hay nadie mirando y no hay que justificar nada.</div><div>Y esa versión merece que le hagas caso.</div><div>Merece que te muevas hacia ella aunque no haya garantías. Aunque sea despacio. Aunque haya obstáculos. Aunque nadie más lo entienda todavía.</div><div>Porque el honor no está en llegar.</div><div>Está en ser de los que lo intentan de verdad. De los que plantan el olivo aunque no sepan si van a ver el fruto. De los que eligen vivir hacia algo en lugar de sobrevivir a algo.</div><div>Eso es lo que queda. No el resultado.</div><div>La manera en que has peleado. La persona en que te has convertido peleando.</div><div>Ana lo sabe.</div><div>Con tierra en las manos y 2 olivos delante y todo el camino que le falta por recorrer todavía. Lo sabe.</div><div>Y sonríe.</div><div>🌱 Soma</div><div><br></div>", "preheader": "¿Alguna vez has plantado algo sabiendo que quizá nunca verías el fruto?"}'::jsonb, '2026-05-11 11:31:36+00'::timestamptz, '{Kit}'::text[], '', '', '23660790', '', '', '2026-05-14 10:13:02.577+00'::timestamptz, '2026-04-19 17:29:16.283215+00'::timestamptz, '2026-05-14 10:13:02.592592+00'::timestamptz) ON CONFLICT (id) DO NOTHING;
INSERT INTO piezas (id, idea_id, titulo, formato, columna, contenido, fecha_publicacion, plataformas, url_publicacion, notas, kit_broadcast_id, instagram_media_id, tematica, last_synced_at, created_at, updated_at) VALUES ('8a21dde7-2c0b-458d-97a1-50267e09f579'::uuid, NULL, 'Storytelling | Nadie viene', 'email', 'agendado', '{"asunto": "Nadie viene a cogerte la mano en la noche oscura", "cuerpo": "Durante mucho tiempo Bruno esperó.<div>No lo habría llamado así, pero eso era lo que hacía.</div><div>Esperaba a que las circunstancias mejoraran. Esperaba a que alguien viera lo que él valía. Esperaba a que llegara el momento correcto, la señal de que era la hora.</div><div>Esperaba con una paciencia que en realidad no era paciencia.</div><div>Era miedo con buena postura.</div><div>Había tenido momentos difíciles.</div><div>Una infancia que no había elegido. Personas que le habían fallado cuando no debían haberle fallado. Situaciones que le habían dejado en sitios desde los que era más difícil salir que entrar.</div><div>Todo eso era verdad. Y Bruno lo usaba.</div><div>No conscientemente ni con maldad.</div><div>Pero lo usaba. Como explicación. Como razón. Como el relato que justificaba por qué todavía no.</div><div>Por qué todavía no había empezado. Por qué todavía no había cambiado. Por qué todavía seguía en el mismo sitio que hace 3 años, que hace 5, que hace 10.</div><div>La noche más difícil de Bruno fue de lo más normal.</div><div>Un martes. El piso en silencio. 38 años. Y de repente, sin que nada lo hubiera provocado, una pregunta.</div><div>¿Y si no viene nadie?</div><div>No como metáfora, sino como hecho concreto.</div><div>¿Y si la persona que te va a cambiar la vida no existe? ¿Y si la oportunidad perfecta no está esperando a que estés listo? ¿Y si llevas 10 años esperando algo que no existe?</div><div>Nadie viene.</div><div>Y no es una crueldad del universo. Simplemente es la estructura real de cómo funcionan las cosas.</div><div>El mundo no está organizado alrededor de Bruno. Ni de ti.</div><div>No hay nadie monitorizando tu situación y esperando el momento de intervenir. No hay una fuerza que compense lo que no ha sido justo. No hay un después en el que todo se equilibra solo.</div><div>Hay esto. Lo que hay ahora. Lo que haces con lo que hay ahora. Las decisiones que tomas o no tomas con lo que tienes o no tienes.</div><div>Solo eso.</div><div>La familia no viene.</div><div>A veces no puede. A veces no sabe. A veces tiene sus propias heridas demasiado abiertas para ocuparse de las tuyas.</div><div>Los amigos no vienen.</div><div>Tienen sus propias noches de martes. Sus propias preguntas sin respuesta. Sus propias vidas que gestionar.</div><div>El sistema no viene.</div><div>El sistema no ha sido diseñado para salvarte, sino para funcionar. Y tú eres una variable dentro de ese funcionamiento.</div><div>Nadie viene.</div><div>Y justo ahí, en ese sitio que parece el más oscuro, está la única cosa que importa.</div><div>Que si nadie viene, entonces eres tú.</div><div>Tú eres el único que puede.</div><div>No porque seas especial o porque tengas unos poderes que los demás no tienen.</div><div>Sino porque eres el único con acceso real a lo que piensas, a lo que sientes, a lo que te frena y a lo que podrías hacer si dejaras de esperar que alguien o algo te lo autorizara.</div><div>Y eso, aunque al principio parece una carga, es lo más parecido a la libertad que existe.</div><div>Bruno se levantó el miércoles sin que nada hubiera cambiado por fuera.</div><div>La misma situación. El mismo piso. Los mismos 38 años.</div><div>Pero con algo distinto dentro: la ausencia de la espera.</div><div>La sensación de ser más ligero.</div><div>Porque llevar años esperando algo que no viene pesa más de lo que uno cree hasta que lo suelta.</div><div>No te voy a decir que es fácil.</div><div>No lo es.</div><div>Hay una soledad que debes atravesar en el momento en el que entiendes que eres tú.</div><div>Pero al otro lado de esa soledad hay algo que no encontrarías de ninguna otra manera.</div><div>La fe de que lo que construyas desde aquí es tuyo de verdad.</div><div>Que no te lo ha dado nadie. Ni depende de que nadie siga dándotelo.</div><div>Nadie viene a salvarte.</div><div>Eso es verdad.</div><div>Pero tú estás aquí. Ahora mismo. Leyendo esto.</div><div>Con todo lo que te ha pasado y todo lo que no te ha pasado y todas las noches difíciles y todas las veces que has esperado algo que no ha llegado.</div><div>Sigues aquí y eso no es poca cosa.</div><div>Eso es que algo dentro de ti no se ha rendido. Que algo dentro de ti sabe que todavía no has empezado de verdad. Que algo dentro de ti lleva tiempo esperando que tú te pongas de tu lado.</div><div>Nadie viene.</div><div>Pero tú ya estás.</div><div>Siempre has sido tú.</div><div>🦋 Soma</div>", "preheader": "Porque esa mano… siempre ha sido la tuya."}'::jsonb, '2026-05-18 11:30:00+00'::timestamptz, '{Kit}'::text[], '', '', '23661113', '', '', '2026-04-19 17:45:00.163+00'::timestamptz, '2026-04-19 17:31:22.021023+00'::timestamptz, '2026-04-20 20:09:42.124788+00'::timestamptz) ON CONFLICT (id) DO NOTHING;
INSERT INTO piezas (id, idea_id, titulo, formato, columna, contenido, fecha_publicacion, plataformas, url_publicacion, notas, kit_broadcast_id, instagram_media_id, tematica, last_synced_at, created_at, updated_at) VALUES ('e54b2b4a-a0c6-49a2-b09a-42c051ad04c8'::uuid, NULL, 'Autoridad | El Fénix', 'email', 'publicado', E'{"asunto": "🔥 El fénix que no quiere ser ceniza", "cuerpo": "La historia del ave fénix nos encanta.<div>Resurge de las cenizas y se transforma en algo más grande que lo que era.</div><div>Suena cojonudo. Así que la contamos y nos lo tatuamos.</div><div>Pero hay una parte de la historia que no nos gusta tanto.</div><div>Para resurgir de las cenizas… primero tienes que ser ceniza.</div><div>No metafóricamente.<br>No me refiero a \\"pasar por momentos difíciles\\".<br>​<br>Hablo de arder. De derrumbarte.<br>De quedarte en el suelo sin saber muy bien qué eres ya ni qué vas a ser. Ceniza.</div><div>Y ahí está el problema.</div><div>Porque la mayoría de nosotros queremos el renacimiento sin el incendio.<br>Queremos la versión 2.0 sin soltar la 1.0.</div><div>Y la industria del desarrollo personal nos lo vende así.</div><div>El método de los 30 días. Y el retiro de fin de semana. Y el sistema que te va a cambiar la vida sin que tengas que quedarte quieto en el fuego más de lo cómodo.</div><div>Pero eso no es transformación. Es puta decoración.</div><div>Construimos sobre lo que no ha ardido todavía. Y lo que no ha ardido no ha sido probado. Así que cuando llega la tormenta de verdad, ya sabemos lo que pasa.</div><div>El problema no es que no quieras cambiar.</div><div>El problema es que queremos el cambio sin el costo real del cambio.</div><div>Y ese precio no siempre es trabajo duro.</div><div>A veces es esperar.<br>A veces es quedarte donde estás más tiempo del que aguantas.<br>A veces es dejar de fingir que ya has cruzado lo que todavía no has cruzado.</div><div>El ave fénix no va con prisa.</div><div>Arde hasta el final.<br>Se convierte en ceniza completamente.<br>Y solo entonces surge algo nuevo.</div><div>Así que te dejo esta pregunta:</div><div>¿hay algo en tu vida donde estás intentando renacer sin haberte permitido arder del todo?</div><div>No tienes que responder en voz alta.</div><div>Pero si Ima, tu voz interior, sabe la respuesta… arde cabrón.</div><div>Arde.</div><div>Guerra y honor ⚔️<br>Soma</div><div>​</div>", "preheader": "Y nos lo tatuamos. Y lo ponemos en Insta. Muy transformador todo."}'::jsonb, '2026-04-22 19:05:04+00'::timestamptz, '{Kit}'::text[], '', '', '23764487', '', '', '2026-05-14 10:13:02.993+00'::timestamptz, '2026-04-20 18:53:25.41829+00'::timestamptz, '2026-05-14 10:13:03.008394+00'::timestamptz) ON CONFLICT (id) DO NOTHING;
INSERT INTO piezas (id, idea_id, titulo, formato, columna, contenido, fecha_publicacion, plataformas, url_publicacion, notas, kit_broadcast_id, instagram_media_id, tematica, last_synced_at, created_at, updated_at) VALUES ('12ea549f-a586-43a8-a2bf-9e9441233ebb'::uuid, NULL, 'Autoridad | Vox Ima', 'email', 'publicado', '{"asunto": "🙏🏼 ¿Cuál es la voz interior más sabia que tienes?", "cuerpo": "Hay una voz que ya conoces.<div>No es la que razona. Ni la que construye la película mental de por qué deberías o no deberías. Tampoco es la que te dice lo que quieres escuchar.</div><div>La otra.</div><div>La que aparece justo cuando estás a punto de decir que sí a algo que sabes que no es tuyo.</div><div>Es la voz más profunda que tienes. La que resuena desde el fondo antes de que la mente le de forma.</div><div>Sócrates la llamaba el daimonion. Los romanos, el Genius. Jung, el Self.</div><div>Cada tradición ha tenido un nombre para lo mismo: esa inteligencia que sabe lo que eres cuando tú mismo lo has olvidado.</div><div>Los Indomables la llamamos Ima.</div><div>Y no te va a convencer de nada.</div><div>No porque no sepa. Sino porque no funciona así.</div><div>Ima no argumenta, ni te da 3 razones por las que deberías cambiar de dirección. No te manda una lista de pros y contras, ni negocia contigo.</div><div>Ima señala.</div><div>Y ahí está el problema que tenemos la mayoría.</div><div>Hemos confundido esa voz con el miedo. Con la inseguridad. Con la resistencia que hay que vencer.</div><div>Hemos aprendido a ignorarla con argumentos perfectamente razonables, y creemos que eso es ser valiente.</div><div>No lo es.</div><div>El miedo habla rápido y con urgencia. Tiene lógica y nos da razones cojonudas.</div><div>Ima no. Ima habla despacio. Con una certeza que no necesita defenderse.</div><div>La diferencia, cuando aprendes a distinguirlas, lo cambia todo.</div><div>Porque no es que no hayas escuchado a Ima hasta ahora.</div><div>La has escuchado muchas veces.</div><div>Lo que pasa es que todavía no tenía nombre. Y lo que no tiene nombre es más fácil de ignorar. Claro.</div><div>Así que te dejo esta pregunta:</div><div>¿qué te dice Ima en este momento de tu vida que llevas un tiempo sin querer escuchar?</div><div>No hace falta que lo respondas aquí, aunque me gustará leerte si te atreves.</div><div>Pero dale un segundo de silencio real. No digo el de estar quieto con el teléfono en la mano.</div><div>El otro.</div><div>Ya sabe lo que sabes.</div><div>Guerra y honor ⚔️<br>Soma</div><div>​</div><div>PD: en La Hermandad Indomable hemos hecho el Sprint IMA durante 10 días de Abril con el objetivo de escucharla con mayor claridad.</div>", "preheader": "Sócrates la escuchaba. Tú también."}'::jsonb, '2026-04-29 11:34:26+00'::timestamptz, '{Kit}'::text[], '', 'Después de la post data hay tres imágenes de testimonios de alumnos del Sprint IMA.', '23779379', '', '', '2026-05-14 10:13:01.304+00'::timestamptz, '2026-04-20 20:09:14.555376+00'::timestamptz, '2026-05-14 10:13:01.320155+00'::timestamptz) ON CONFLICT (id) DO NOTHING;
INSERT INTO piezas (id, idea_id, titulo, formato, columna, contenido, fecha_publicacion, plataformas, url_publicacion, notas, kit_broadcast_id, instagram_media_id, tematica, last_synced_at, created_at, updated_at) VALUES ('e597cb8a-3dc0-4da3-957e-b2853a2d33dd'::uuid, '4a8e71ca-66b8-4b74-ac6c-2c85982084fd'::uuid, 'Lo que 4 Millones de Euros me han Enseñado', 'youtube', 'desarrollo', E'{"guion": "<div>GUIÓN: \\"Puedes facturar más este año. Y seguir siendo un peón.\\"</div><div>Formato: YouTube, 8-12 minutos. Talking head, cámara directa, entorno real. Sin música. Silencios tácticos largos. Ropa de casa o sencilla. Cámara trasera 4K.<br>Packaging recomendado:<br>&nbsp;•\\tTítulo: Puedes facturar más este año. Y seguir siendo un peón.<br>&nbsp;•\\tTitulo: Lo que 4 Millones de Euros me han enseñado.<br>&nbsp;•\\tThumbnail: Soma de frente, expresión grave, texto mínimo \\"Facturar ≠ Poseer\\", fondo blanco o neutro que invierta la meta del nicho. Prueba del zoom al 10%.<br>&nbsp;•\\tTexto en pantalla durante el hook: \\"El espejo que nadie quiere mirar.\\"</div><div>[GANCHO VISUAL — 0:00]<br>(Silencio. 3 segundos. Contacto visual fijo. Sin música. El silencio es el primer gancho.)</div><div>[HOOK HABLADO — 0:03-0:25]<br>Puedes facturar más este año que cualquier año anterior.<br>Más clientes.<br>Más proyectos.<br>Más dinero entrando.<br>Y seguir siendo un peón.<br>(Pausa.)<br>No un peón pobre.<br>Un peón bien pagado.<br>Que es la versión más cara de lo mismo.<br>(Pausa.)<br>Yo lo he hecho.<br>Durante mucho tiempo pensé que estaba ganando, ganando-bro-masivo… y llegué a facturar más de 4 millones de euros con mis negocios… hasta que aprendí estas 4 lecciones por las malas.</div><div>[CONFIRMACIÓN DEL CLIC — 0:25-1:00]<br>Esto no es un video sobre cómo ganar más dinero.<br>El dinero ya lo vas a conseguir.<br>El problema es que la mayoría de nosotros lo estamos construyendo de una forma que no nos da lo que creemos que nos va a dar.<br>Lo que el dinero me ha enseñado a mí no es cómo acumularlo.<br>Me ha enseñado a mirarlo como un espejo.<br>Porque el dinero no solo muestra cuánto ganas.<br>Muestra si dependes o no dependes.<br>Si posees algo o solo produces para otros.<br>Si estás construyendo libertad… o una cárcel mejor decorada.<br>(pausa)<br>Hay una narrativa muy peligrosa ahí fuera.<br>“Gana más dinero.” “Escala.” “Facturación.” “Libertad financiera.”<br>(pausa)<br>Y sí… el dinero importa.<br>Pero lo que no te dicen es que no todo el dinero te acerca a la libertad.<br>(pausa)<br>Hay dinero que te expande… y hay dinero que te encadena.<br>(pausa)<br>Y lo más jodido es que, desde fuera, parecen exactamente iguales.<br>Y hay cuatro verdades sobre el dinero que nadie te dice.<br>Porque incomodan.</div><div>[VERDAD 1 — \\"Facturar no es poseer\\"] — 1:00-3:00<br>Durante 2 años seguidos estuve facturando por encima de los cien mil euros al mes.<br>El estilo de vida. Los viajes. El deportivo. Los empleados.<br>Todo en su sitio.<br>Y en 2021 me di cuenta de que si decidía parar 6 meses se caia todo.<br>(Pausa larga.)<br>Eso no es un imperio, por mucho que brille.<br>Eso es un trabajo con mejor nombre.<br>(Pausa.)<br>La mayoría de nosotros confundimos facturación con construcción.<br>Creemos que si entra más caja, estamos ganando el juego.<br>Y a veces sí.<br>Pero a veces lo único que estamos haciendo es producir más… para que otros posean más.<br>El dinero que, cuando paramos, desaparece como si nunca hubiera existido… ese dinero no construye soberanía personal. No construye una vida indomable.<br>Te mantiene vivo. Que es necesario.<br>Pero no es suficiente.<br>Porque durante mucho tiempo te vendes la película de que estás creciendo… cuando en realidad solo estás sosteniendo una máquina que te necesita cada día para no caerse.<br>Asi que la pregunta no es cuánto entra.<br>La pregunta es qué queda cuando tú dejas de empujar.<br>Si la respuesta es nada, no tienes un negocio.<br>Tienes una rueda que necesita que estés corriendo dentro para moverse. No es la carrera de la rata, es la carrera de XXXXXXXXXXXX.</div><div>[RE-HOOK — 3:00]<br>Pero hay algo peor que facturar sin poseer.<br>Y es lo que más nos cuesta reconocer.</div><div>[VERDAD 2 — \\"Hay dinero que te rompe por dentro\\"] — 3:05-5:30<br>A inicios de 2023 tuve que elegir entre dos caminos.<br>Uno pagaba bien.<br>El otro era mío.<br>Y durante 2 años (mucho más de lo que me gusta admitir…) elegí el que pagaba bien.<br>(Pausa.)<br>No porque no supiera lo que quería.<br>Lo sabía perfectamente.<br>Lo elegí porque la seguridad pesa más cuando tienes miedo.<br>Y ese dinero entró, unos 400 mil euros.<br>Y pagó cosas.<br>Y por fuera todo tenía buena pinta. Y en Andorra iba a los restaurantes caros.<br>Pero por dentro había algo que se estaba astillando.<br>Algo que se rompía cada vez que tomaba una decisión desde la supervivencia en lugar de desde mi centro.<br>(Pausa.)<br>Hay dinero limpio.<br>El que entra alineado con lo que eres y con lo que tu alma quiere construir.<br>Y hay dinero que te rompe por dentro.<br>El que exige que vendas tu tiempo, tu paz, tu identidad, o tu verdad para conseguirlo.<br>El primero te expande.<br>El segundo tiene un precio que no aparece en ninguna factura.<br>Y ese precio lo pagas con algo que no se recupera con facilidad.<br>Con la confianza en tu propia palabra.<br>Dinero que te exige:<br>&nbsp;•\\tdecir cosas que no piensas<br>&nbsp;•\\tmantener relaciones que no quieres<br>&nbsp;•\\tsostener estructuras que te drenan<br>&nbsp;•\\to vivir de una forma que no es la tuya<br>Es más, me encantará leer en los comentarios si algo de esto está resonando contigo.<br>Y la trampa es que desde fuera, ese dinero parece éxito.<br>Pero por dentro… te está alejando de ti.<br>(pausa)<br>Y el problema no es moral.<br>Es estructural.<br>Porque cada euro, peso o dólar que ganas traicionándote… refuerza una vida que luego no puedes sostener sin seguir traicionándote.<br>Y eso sale carísimo.<br>Mucho más caro que lo que cobras.</div><div>[RE-HOOK — 5:30]<br>La tercera verdad es la que más confunde a los hombres que ya han entendido las dos primeras.</div><div>[VERDAD 3 — \\"Escalar es una trampa disfrazada de ambición.\\"] — 5:35-7:30<br>En 2019 entré a un nuevo grupo mastermind.<br>Me costaba quince mil euros al año.<br>Y valió la pena. Aprendí mucho.<br>Pero había algo en ese entorno que me empezó a incomodar sin que supiera exactamente qué era.<br>(Pausa.)<br>Era el discurso.<br>Un solo discurso.<br>Escalar.<br>Escalar.<br>Escalar.<br>Si hablabas de una acción que funcionaba en tu negocio, la primera pregunta era siempre la misma:<br>\\"¿Pero eso escala?\\"<br>Y si la respuesta era no… era como si la acción no valiera.<br>Como si no contara. Ah Soma, cuidado, que esto no escala.<br>(Pausa.)<br>En 2023 me fui.<br>No porque el grupo fuera malo.<br>Me fui porque llevaba años persiguiendo esa idea…y lo que había conseguido era 13 empleados a jornada completa. Diez freelances. Un negocio que facturaba más de 1 kilo al año.<br>Y yo gestionando.<br>Gestionando.<br>Gestionando.<br>Sin crear.<br>(Pausa larga.)<br>Y lo que a mí me enciende… es crear.<br>Escalar me alejó de lo único que me importaba.<br>Escalé una empresa que no era yo.<br>Era la versión de mí que el discurso quería que fuera.<br>(Pausa.)<br>Ahora estoy en Andorra.<br>Tengo amigos con negocios digitales, youtubers, creadores.<br>El discurso sigue siendo el mismo.<br>Escalar.<br>Escalar.<br>Escalar.<br>Y yo ya he aprendido algo que nadie me dijo pagando quince mil euros al año de mentoría.<br>No todo tiene que escalar.<br>Hay acciones que no escalan… y son exactamente lo que tu negocio necesita.<br>Hay un tamaño de negocio que te hace libre… y otro que te hace prisionero aunque facture más.<br>Si eres feliz con un negocio de cincuenta mil al año… eso no es conformismo.<br>Puede ser inteligencia.<br>Puede ser soberanía personal.&nbsp;<br>Puede ser saber exactamente lo que quieres sin pedir permiso para quererlo.<br>Puede ser vivir en tus putos términos. Eso es una Vida Indomable joder!<br>(Pausa.)<br>El discurso de escalar te convence de que donde estás nunca es suficiente.<br>No confundas ambición con tamaño.<br>La ambición real es construir algo que sea completamente tuyo.<br>Aunque no tenga 13 empleados.<br>Aunque no \\"escale\\".</div><div>[RE-HOOK — 7:30]<br>Y hay una cuarta verdad que une todo esto.<br>La más incómoda de todas.</div><div>[VERDAD 4 — \\"El dinero es el espejo más brutal que existe\\"] — 7:35-9:30<br>El dinero no miente.<br>Nosotros sí.<br>Nosotros nos decimos que somos libres cuando no lo somos.<br>Que somos dueños cuando solo producimos.<br>Que estamos construyendo cuando solo estamos sobreviviendo con más clase.<br>El dinero no nos sigue la corriente.<br>El dinero nos muestra, con una claridad que duele, exactamente quién manda en nuestra vida.<br>(Pausa.)<br>Si dependes de un cliente para respirar…<br>el dinero te lo muestra.<br>Si no puedes decir que no porque necesitas la caja…<br>el dinero te lo muestra.<br>Si aceptas condiciones que te rompen porque tienes miedo de lo que pasa si no las aceptas…<br>el dinero te lo muestra.<br>(Pausa larga.)<br>No hay nada malo en eso.<br>La mayoría de nosotros hemos estado ahí.<br>Yo he estado ahí.<br>Pero hay que mirarlo.<br>Porque el primer movimiento para salir…<br>es dejar de mentirse sobre dónde se está.<br>(Pausa.)<br>El dinero no revela cuánto ganas.<br>Revela quién manda en tu vida.<br>Y si lo que revela no te gusta…<br>eso no es una sentencia.<br>Es el diagnóstico.<br>Y los diagnósticos sirven para algo.</div><div>[CIERRE — RAMPA, no adiós] — 9:30-10:00<br>Cuatro verdades.<br>Facturar no es poseer.<br>Hay dinero que te rompe por dentro.<br>Escalar no es ambición.<br>Y el dinero es el espejo más brutal que existe.<br>No te las digo para que te sientas mal.<br>Te las digo porque la mayoría de nosotros llevamos años persiguiendo más caja… sin preguntarnos qué tipo de dinero estamos construyendo.<br>Puedes ganar mucho dinero…y seguir siendo un peón.<br>(pausa)<br>Yo lo he sido.<br>(pausa)<br>Y la diferencia no está en cuánto ganas.<br>(pausa)<br>Está en si ese dinero:<br>&nbsp;•\\tte da estructura<br>&nbsp;•\\tte da propiedad<br>&nbsp;•\\tte da margen<br>&nbsp;•\\tte da centro<br>(pausa)<br>o si solo te obliga a seguir corriendo para no perderlo.<br>(pausa final)<br>Porque hay dos tipos de crecimiento:<br>el que te expande…y el que te encierra.<br>(pausa)<br>Y eso… no se ve en la facturación.<br>Y hay una diferencia enorme entre generar ingresos y construirnos una vida en nuestros términos.<br>(Pausa.)<br>Si esto resonó…<br>no porque sea nuevo.<br>Sino porque ya lo sabías y nunca lo habías visto tan claro.<br>Lo que trabajamos en La Hermandad va mucho más allá de esto.<br>El enlace está abajo.<br>Guerra y honor ⚔️<br>Soma</div>", "titulo_video": "Lo que 4 Millones de Euros me han Enseñado"}'::jsonb, NULL, '{YouTube}'::text[], '', 'Notas de producción
Silencios: Las pausas marcadas en el guión no son opcionales. Son el gancho de audio. El silencio antes del hook, el silencio después de "se cae todo", el silencio antes de "el dinero no miente". Esos silencios tienen más peso que cualquier música motivacional.
Texto en pantalla (term branding): Solo en las frases clave. Letra grande, minimalista:
 • "Facturar no es poseer."
 • "El dinero que te rompe por dentro."
 • "Intensidad ≠ estructura."
 • "El dinero revela quién manda en tu vida."
Entorno: Real. Tu espacio habitual. Sin decoración de "creador de contenido". Ropa de casa o sencilla. La producción sobria es el packaging correcto para este mensaje.
Thumbnail: Soma de frente, expresión grave, sin sonrisa. Fondo blanco o neutro claro que contraste con los fondos oscuros habituales del nicho. Texto mínimo: "Facturar ≠ Poseer" o "El espejo que nadie quiere mirar." Sin efectos. Sin marcos de colores. La austeridad es el contraste.', '', '', '', NULL, '2026-04-20 22:20:35.786169+00'::timestamptz, '2026-04-20 22:20:35.786169+00'::timestamptz) ON CONFLICT (id) DO NOTHING;
INSERT INTO piezas (id, idea_id, titulo, formato, columna, contenido, fecha_publicacion, plataformas, url_publicacion, notas, kit_broadcast_id, instagram_media_id, tematica, last_synced_at, created_at, updated_at) VALUES ('ceea96a3-95b6-4094-ad7a-8b46163106db'::uuid, '4a8e71ca-66b8-4b74-ac6c-2c85982084fd'::uuid, 'Autoridad | 4 Millones de Euros', 'email', 'publicado', '{"asunto": "💰 Puedes ganar mucho dinero… y seguir siendo un peón", "cuerpo": "<div>Durante 2 años seguidos facturé por encima de los 100.000€ al mes.</div><div>El deportivo. Los viajes en primera. Los empleados. Todo en su sitio.</div><div>Y un día de 2021 me hice una pregunta simple: ¿qué pasa si paro 6 meses?</div><div>La respuesta fue clarísima: se caía todo.</div><div>Ahí aprendí que facturar (por muy alta que sea la cifra), no es poseer.</div><div>Y que eso no es un imperio, por mucho que brille. Eso es un trabajo con mejor nombre.</div><div>​</div><div>La mayoría de nosotros confundimos facturación con construcción.<br>Creemos que si entra más caja, estamos ganando el juego. Y a veces sí. Pero a veces lo único que hacemos es producir más… para que otros posean más.</div><div>El dinero que desaparece cuando paras no construye soberanía personal.</div><div>Te mantiene vivo. Que es necesario. Claro.</div><div>Pero no es suficiente.</div><div>Y hay algo que nadie te dice sobre el dinero porque incomoda demasiado 👇🏼</div><div>​</div><div>No todo el dinero te acerca a la libertad.<br>Hay dinero que te expande. El que entra alineado con lo que eres y con lo que quieres construir.</div><div>Te da estructura. Y centro. Y margen para decir que no.</div><div>Y hay dinero que te rompe por dentro.</div><div>El que exige que vendas tu tiempo, tu paz o tu verdad para conseguirlo. El que desde fuera parece éxito… y por dentro te está alejando de ti.</div><div>​</div><div>Yo lo he pagado.<br>A inicios de 2023 tuve que elegir entre 2 caminos.</div><div>Uno pagaba bien. El otro era mío.</div><div>Y durante 2 años (mucho más de lo que me gusta admitir) elegí el que pagaba bien: 400.000€.</div><div>Pero el precio que pagué no apareció en ninguna factura.</div><div>Lo pagué con algo que no se recupera fácil: la confianza en mi propia palabra.</div><div>Así que la pregunta no es cuánto entra.</div><div>La pregunta es qué tipo de dinero estás construyendo.</div><div>Porque puedes ganar mucho dinero…y seguir siendo un peón. Como en mi caso.</div><div>Y la diferencia no está en cuánto ganas.</div><div>Está en si ese dinero te da estructura. Si te da propiedad. Si te da margen. Y si te da centro vital.</div><div>O si solo te obliga a seguir corriendo para no perderlo.</div><div>Y eso… no se ve en la facturación.</div><div>​</div><div>El dinero no revela cuánto ganas.<br>Revela quién manda en tu vida.</div><div>Y si lo que revela no te gusta… eso no es una sentencia.</div><div>Es el diagnóstico.</div><div>Y los diagnósticos sirven para algo.</div><div>Guerra y honor ⚔️<br>Soma</div>", "preheader": "Ganaba más de 100.000€ al mes y seguía sin tener nada."}'::jsonb, '2026-05-06 18:00:26+00'::timestamptz, '{Kit}'::text[], '', '', '23782065', '', '', '2026-05-14 10:13:01.756+00'::timestamptz, '2026-04-20 22:44:41.228892+00'::timestamptz, '2026-05-14 10:13:01.772901+00'::timestamptz) ON CONFLICT (id) DO NOTHING;
INSERT INTO piezas (id, idea_id, titulo, formato, columna, contenido, fecha_publicacion, plataformas, url_publicacion, notas, kit_broadcast_id, instagram_media_id, tematica, last_synced_at, created_at, updated_at) VALUES ('80db650f-d6e0-41e8-b93d-63079b02bd10'::uuid, '103a7f60-af01-435c-bac3-ea3a672b57bc'::uuid, 'Por qué eres Vago | URGENTE', 'youtube', 'desarrollo', E'{"guion": "<div>Guión fusionado</div><div>\\"La verdad incómoda sobre por qué la mayoría de la gente es vaga\\"<br>Formato: YouTube, 8-12 minutos. Talking head, cámara directa, entorno real. Sin música. Silencios tácticos largos. Cámara trasera 4K.<br>Packaging:<br>&nbsp;•\\tTítulo: La verdad incómoda sobre por qué eres vago<br>&nbsp;•\\tThumbnail: Soma de frente, expresión grave, texto en pantalla \\"No es pereza\\". Fondo neutro que invierta la meta del nicho. Prueba del zoom al 10%.<br>&nbsp;•\\tTexto en pantalla durante el hook: \\"No necesitas otro truco para madrugar.\\"</div><div>[GANCHO VISUAL — 0:00]<br>(Silencio. 3 segundos. Contacto visual fijo. Sin música.)</div><div>[HOOK HABLADO — 0:03-0:20]<br>Durante muchos años pensé que era vago.<br>(pausa)<br>Que tenía un problema de disciplina. De enfoque. Cuando tenía que ir a la universidad me quedaba a dormir en el coche. Cuando tenía que despertarme a las 6 de la mañana para ir a trabajar, llamaba diciendo que estaba enfermo.<br>(pausa)<br>No.<br>(pausa)<br>No eres vago. No tienes un “problema de procrastinación”. Y definitivamente no necesitas ver otro vídeo con trucos para madrugar.<br>(pausa)<br>La verdad es más incómoda:<br>Estás intentando construir una vida que no respetas.</div><div>[CONFIRMACIÓN DEL CLIC — 0:20-1:00]<br>Hay dos discursos ahí fuera igual de peligrosos.<br>Uno te dice: \\"aprieta más, disciplina, levántate a las 5\\".<br>El otro te dice: \\"descansa, fluye, date permiso\\".<br>(pausa)<br>Y hay momentos donde los dos tienen sentido.<br>Pero la mayoría de nosotros los estamos usando como excusa.<br>(pausa)<br>Después de años construyendo, equivocándome y observando esto en mí y en otros… entendí lo que nos mantiene pegados al sofá: la pereza no es el problema. Es un síntoma. Un sistema de alerta.<br>Y casi siempre apunta a lo mismo.<br>(pausa)<br>Falta de soberanía personal, de liderazgo personal.<br>(pausa)<br>Hoy voy a destrozar la mentira de la \\"falta de motivación\\" y te voy a mostrar las cinco causas reales que te mantienen apagado. No son problemas de gestión del tiempo. Son problemas de verdad.</div><div>[CAUSA 1 — \\"Estás persiguiendo objetivos que no son tuyos\\"] — 1:00-2:30<br>Primera causa.<br>(pausa)<br>Estás persiguiendo objetivos que no son tuyos.<br>(pausa larga)<br>Metas heredadas. Metas que suenan bien. Metas que encajan en Instagram. Metas que te hacen sentir validado… pero no vivo.<br>(pausa)<br>Quieres facturar más… pero no sabes para qué.<br>Quieres \\"crecer\\"… pero no sabes hacia dónde.<br>Quieres resultados… que en el fondo ni te importan.<br>(pausa)<br>Y tu sistema interior no es tonto.<br>No te va a dar energía para construir una vida que no sientes como tuya.<br>(pausa)<br>Hay una voz dentro de ti que sabe perfectamente cuándo lo que persigues es tuyo y cuándo no lo es.<br>Esa voz no grita. No argumenta. No te da tres razones.<br>Simplemente te quita la energía.<br>(pausa)<br>La motivación no aparece cuando algo es fácil.<br>Aparece cuando hay verdad.<br>Y si lo que tienes delante no tiene verdad… tu cuerpo lo sabe antes que tu cabeza.</div><div>[RE-HOOK — 2:30]<br>Pero hay una segunda causa que es peor. Porque esta te la escondes a ti mismo.</div><div>[CAUSA 2 — “El veneno del resentimiento”] — 2:35-4:15<br>Estás cargando más resentimiento del que admites.<br>Resentimiento hacia otros. Hacia el sistema. Hacia ti mismo.<br>El resentimiento no es ruidoso. Es lento. Te deja apagado. Cínico. Sin hambre.<br>Y te consume sin que lo veas, porque no parece un problema. Parece un estado.<br>(pausa)<br>Aquí hay una verdad que duele: el resentimiento es tóxico y te consume vivo pero es una brújula perfecta. Si estás resentido, solo hay dos opciones.&nbsp;<br>O alguien te está oprimiendo y no tienes el valor de defenderte... o te estás comportando como un niño llorón que cree que el mundo le debe algo.<br>(pausa)<br>No me corresponde a mí decirte cuál de las dos es la tuya. Eso lo sabes tú.<br>Pero lo que sí te digo es que en ambos casos te quedas sin energía.<br>Y en ambos casos la salida es la misma: acción. No terapia pasiva. No reflexión infinita.<br>(pausa)<br>¿Te oprimen? Lucha y defiéndete. ¿Eres un llorón? Madura y asume la responsabilidad radical de que el mundo no te debe nada y que nadie viene a salvarte.<br>(pausa)<br>Porque el resentimiento se disuelve cuando empiezas a construir algo que respetas. No antes.</div><div>[RE-HOOK — 4:15]<br>La tercera causa es la que más jode. Porque la mayoría de nosotros la hemos vivido creyendo que estábamos haciendo lo correcto.</div><div>[CAUSA 3 — \\"Has convertido la disciplina en castigo\\"] — 4:20-5:50<br>Has entendido la disciplina como algo negativo y le tienes miedo a tu propio poder.<br>(pausa)<br>El Hombre Domesticado se cree que la disciplina es un castigo. Que es un sacrificio. Que es privarse de cosas. Como una vida gris donde te arrancas lo que quieres para demostrar que eres fuerte.<br>(pausa)<br>Así nadie sostiene nada durante el tiempo suficiente. Y ahí está la trampa.<br>(pausa)<br>Porque la industria del desarrollo personal te ha vendido la disciplina como obediencia. \\"Haz esto todos los días aunque no quieras.\\" \\"Machaca.\\" \\"Sin excusas.\\"<br>(pausa)<br>Eso no es disciplina. Eso es domesticación.<br>(pausa)<br>La disciplina real no es privarte de nada.<br>Es decidir quién manda.<br>(pausa)<br>Cada vez que dices que vas a hacer algo y no lo haces… no te falta fuerza de voluntad.<br>Estás demostrándole a tu animal interno quién lleva la puta corona.<br>Te estás entrenando para no confiar en tu propia palabra.<br>(pausa)<br>Y un hombre que no confía en su propia palabra… se convierte en esclavo de si mismo.<br>No porque sea vaga. Porque ha perdido autoridad sobre sí misma. Y los esclavos no construyen imperios.<br>(pausa)<br>No es un problema de motivación. Es un problema de confianza interna destrozada a base de promesas rotas… contigo mismo.</div><div>[RE-HOOK — 5:50]<br>La cuarta causa es la más simple de entender y la más difícil de admitir.</div><div>[CAUSA 4 — \\"No tienes una guerra digna\\"] — 5:55-7:15<br>No tienes algo delante que te exija crecer.<br>(pausa)<br>Y sin eso… te apagas.<br>(pausa)<br>No necesitas motivación. Necesitas algo que haga que la versión actual de ti no sea suficiente.<br>(pausa)<br>Algo que te obligue a convertirte en alguien que todavía no eres para poder sostenerlo.<br>(pausa)<br>Si lo que tienes delante es pequeño… tu energía también lo será.<br>(pausa)<br>Si tus objetivos no requieren que evoluciones, no son objetivos. Son un trámite. Y nadie se levanta por la mañana emocionado por hacer trámites.<br>(pausa)<br>Y aquí es donde hay que distinguir algo importante.<br>No hablo de \\"metas ambiciosas\\" en el sentido de facturar un millón o tener un equipo de quince personas.<br>Hablo de algo que te importe lo suficiente como para que levantarte tenga sentido aunque nadie te aplauda por ello.<br>(pausa)<br>Eso no se encuentra en un ejercicio de visualización.<br>Se encuentra cuando dejas de perseguir lo que suena bien y empiezas a construir lo que de verdad te enciende.<br>(pausa)<br>Y si no sabes qué es… eso ya es el problema. No la pereza.</div><div>[RE-HOOK — 7:15]<br>Y la quinta causa es la más profunda. La que casi nadie quiere tocar.</div><div>[CAUSA 5 — “Los fantasmas del pasado”] — 7:20-8:45<br>Hay gente que no avanza no porque sea débil.<br>Sino porque está congelada por el terror o la vergüenza de un fracaso o de un trauma antiguo que no se ha mirado de frente.<br>(pausa)<br>Y eso es real. No es excusa. Es real.<br>(pausa corta)<br>Pero aquí hay un matiz que cambia todo:<br>Si conviertes ese dolor en tu identidad… te quedas ahí para siempre.<br>El pasado no desaparece solo y los Indomables no huimos de él. Lo confrontamos. Deconstruimos el dolor hasta extraer el mapa táctico que nos garantiza que deja de mandarnos.<br>No para que deje de doler.<br>Para que deje de mandarnos.<br>(pausa)<br>Porque el dolor no procesado paraliza. Pero el dolor trabajado te estructura.<br>Y esa diferencia… es la diferencia entre alguien atrapado y alguien peligroso en el mejor sentido.</div><div>[CAMBIO DE PARADIGMA — 8:45-9:45]<br>(pausa larga)<br>Deja de buscar motivación.<br>La motivación es inestable. Es emocional. Es volátil. Es el azúcar del desarrollo personal. Es para niños.<br>(pausa)<br>Lo que necesitas es claridad.<br>(pausa)<br>Claridad sobre qué quieres de verdad. Qué estás evitando. Qué estás sosteniendo por miedo. Y qué estás llamando \\"pereza\\"… cuando en realidad es incoherencia.<br>(pausa larga)<br>La pereza no es una enfermedad, es un síntoma.<br>No eres vago joder. Solo estás desalineado.<br>(pausa)<br>Y hay una forma de saberlo siempre.<br>(pausa)<br>Si tienes que convencerte de que lo que persigues te importa… no te importa.<br>Cuando te importa de verdad, no necesitas convencerte. Lo sabes en el cuerpo antes que en la cabeza.</div><div>[CIERRE — 9:45-11:00]<br>Tu energía no sigue tus objetivos.<br>(pausa)<br>Sigue tu verdad.<br>(pausa)<br>Así que puedes intentar motivarte todo lo que quieras. Puedes descargar otra app. Probar otro sistema. Leer otro libro sobre hábitos.<br>(pausa)<br>Pero si lo que estás construyendo no tiene sentido para ti… no va a funcionar.<br>(pausa)<br>Porque dejar de ser \\"vago\\" no es un problema de disciplina.<br>(pausa)<br>Es un problema de soberanía.<br>(pausa larga)<br>Y la pregunta no es cómo te motivas.<br>La pregunta es si vas a seguir viviendo una vida que no respetas… o si vas a empezar a construir una que sí.<br>(pausa final)<br>Si esto te ha resonado… no porque sea nuevo. Sino porque ya lo sabías y no lo habías visto así.<br>Lo que trabajamos en La Hermandad empieza exactamente aquí.<br>El enlace está en la descripción.<br>Guerra y honor ⚔️ Soma</div><div><br></div><div><br></div><div><br></div><div><br></div><div><br></div><div><br></div><div><br></div><div><br></div><div><br></div><div><br></div><div><br></div>", "titulo_video": "La verdad incómoda sobre por qué eres vago"}'::jsonb, NULL, '{YouTube}'::text[], '', 'El dia X se envía un mail con un link a este video en YT.', '', '', '', NULL, '2026-04-21 12:56:52.447565+00'::timestamptz, '2026-04-21 13:31:46.828911+00'::timestamptz) ON CONFLICT (id) DO NOTHING;
INSERT INTO piezas (id, idea_id, titulo, formato, columna, contenido, fecha_publicacion, plataformas, url_publicacion, notas, kit_broadcast_id, instagram_media_id, tematica, last_synced_at, created_at, updated_at) VALUES ('d3f06343-60bf-476e-a89e-06a61ac43c72'::uuid, '103a7f60-af01-435c-bac3-ea3a672b57bc'::uuid, 'Autoridad | Por qué eres Vago', 'email', 'publicado', '{"asunto": "😮‍💨 Por qué no tienes energía (y cómo recuperarla)", "cuerpo": "Durante muchos años pensé que era vago.<div>Que tenía un problema de disciplina. O de enfoque.</div><div>Cuando tenía que ir a la universidad me quedaba a dormir en el coche. Cuando tenía que levantarme a las 6 am para trabajar, llamaba diciendo que estaba enfermo.</div><div>Pero no era pereza.</div><div>Es que estaba intentando construir una vida que no respetaba.</div><div>Y probablemente tú también.</div><div>Porque la pereza no es un problema. Es un síntoma.</div><div>Es un sistema de alerta que casi siempre apunta a lo mismo: la falta de soberanía personal.</div><div>Tu sistema no es tonto.</div><div>No te va a dar energía para perseguir metas que has heredado, ni metas que te hacen sentir validado… pero no vivo.</div><div>Quieres facturar más pero no sabes para qué.<br>Quieres crecer pero no sabes hacia dónde.<br>Y tu cuerpo lo sabe antes que tu cabeza.</div><div>Hay más 👇🏼</div><div>​</div><div>No tienes algo delante que te exija crecer.<br>Y sin eso te apagas. Tú y todos.</div><div>Si lo que tienes delante es pequeño… tu energía también lo será.</div><div>Si tus objetivos no requieren que evoluciones, no son objetivos. Son un trámite. Y nadie se levanta por la mañana emocionado por hacer trámites.</div><div>Hablo de algo que te importe lo suficiente como para que levantarte tenga sentido aunque nadie te aplauda por ello.</div><div>Eso no se encuentra en un ejercicio de visualización.</div><div>Se encuentra cuando dejas de perseguir lo que suena bien y empiezas a construir lo que de verdad te enciende.</div><div>Y si no sabes qué es… eso ya es el problema. No la pereza.</div><div>Hay más.</div><div>​</div><div>Estás cargando más resentimiento del que admites.<br>Hacia otros, hacia el sistema y/o hacia ti mismo.</div><div>La putada es que el resentimiento no es ruidoso… sino lento. Te deja apagado. Cínico. Sin hambre.</div><div>Y si estás resentido, solo hay 2 opciones: o alguien te está oprimiendo y no tienes el valor de defenderte... o te estás comportando como un niño llorón que cree que el mundo le debe algo.</div><div>No me corresponde a mí decirte cuál de las 2 es la tuya. Eso lo sabes tú.</div><div>Pero lo que sí te digo es que en ambos casos te quedas sin energía.</div><div>Y en ambos casos la salida es la misma: acción. Ni terapia pasiva. Ni reflexión infinita.</div><div>¿Te oprimen? Lucha y defiéndete como puedas y sepas.</div><div>¿Eres un llorón? Madura y asume la responsabilidad radical de que el mundo no te debe nada y que nadie viene a salvarte.</div><div>Hay más 👇🏼<br>​</div><div>Convertir la disciplina en castigo. Los fantasmas del pasado.<br>Pero no quiero alargarme ahora.</div><div>La cosa es que la motivación no es la respuesta. Es el azúcar del desarrollo personal.</div><div>Lo que necesitas es claridad.</div><div>Sigue tu verdad.</div><div>Guerra y honor ⚔️<br>Soma</div><div>​</div><div>​PD: si quieres identificar la verdad incómoda sobre por qué eres vago y sus 5 causas, he grabado esto para ti.</div>", "preheader": "No eres vago. Es otra cosa."}'::jsonb, '2026-05-13 16:01:25+00'::timestamptz, '{Kit}'::text[], '', '⚠️ Tiene un enlace al video de YT "Por qué eres Vago". Es crítico que esté publicado este video y actualizado el enlace en el mail.', '23789298', '', '', '2026-05-14 10:13:01.543+00'::timestamptz, '2026-04-21 13:48:30.431988+00'::timestamptz, '2026-05-14 10:13:01.560975+00'::timestamptz) ON CONFLICT (id) DO NOTHING;
INSERT INTO piezas (id, idea_id, titulo, formato, columna, contenido, fecha_publicacion, plataformas, url_publicacion, notas, kit_broadcast_id, instagram_media_id, tematica, last_synced_at, created_at, updated_at) VALUES ('d6078a48-687c-4b28-ac25-66050d19c7d8'::uuid, NULL, 'Backstage | Neumonía', 'email', 'publicado', '{"asunto": "El universo tiene sentido del humor", "cuerpo": "Te escribo desde el sofá.<div>Llevo 10 días con una neumonía que, al principio, no sabía que era neumonía.</div><div>Primero pensé que era un resfriado raro.<br>Luego pensé que era algo de la garganta.</div><div>Pero cuando vi que empeoraba fui a urgencias, y me dijeron que era una infección seria en los pulmones y que tenía que parar.</div><div>Parar.</div><div>El miércoles te escribí sobre el fénix.<br>Sobre quedarse en el fuego.<br>Sobre no escapar del incendio antes de tiempo.</div><div>Y llevo 10 días literalmente sin poder respirar bien.</div><div>El universo tiene sentido del humor.</div><div>Lo que más me ha costado esta semana no ha sido el dolor, ni la tos, ni encontrarme hecho papilla.</div><div>Ha sido lo otro.</div><div>El no poder hacer nada más que estar quieto.</div><div>El ver pasar los días sin avanzar en lo que tenía entre manos. El no saber cuándo va a terminar.</div><div>Exactamente lo que le pido a la gente que soporte.</div><div>No sé si esto te pasa a ti, pero a mí me cuesta muchísimo predicar lo que no estoy viviendo. Y esta semana el universo se ha encargado de que lo viva.</div><div>Así que la pregunta que me quedo ahora es simple:</div><div>¿cuánto de lo que digo soy capaz de sostener cuando me toca a mí?</div><div>No lo tengo resuelto. Solo lo estoy mirando.</div><div>¿Y tú? ¿Qué pregunta sobre ti y tu vida te quedas esta semana?</div><div>Responde a este email. Leo todo.</div><div>Guerra y honor ⚔️<br>Soma</div><div><br></div>", "preheader": "Llevo 10 días con los pulmones ardiendo."}'::jsonb, '2026-04-24 07:30:29+00'::timestamptz, '{Kit}'::text[], '', 'Probando a enviar temprano a ver cómo funciona, porque viernes x la noche creo que la gente estará fuera.', '23790332', '', '', '2026-05-14 10:13:01.956+00'::timestamptz, '2026-04-21 14:27:16.375636+00'::timestamptz, '2026-05-14 10:13:01.972717+00'::timestamptz) ON CONFLICT (id) DO NOTHING;
INSERT INTO piezas (id, idea_id, titulo, formato, columna, contenido, fecha_publicacion, plataformas, url_publicacion, notas, kit_broadcast_id, instagram_media_id, tematica, last_synced_at, created_at, updated_at) VALUES ('9e95f4e9-7ab6-45cb-8aef-470dd31e7032'::uuid, NULL, 'Backstage | Silvia loca', 'email', 'publicado', '{"asunto": "¿Me estaré volviendo loca?", "cuerpo": "Esta semana Silvia escribió esto en La Hermandad:<div>“No sé si tengo 2 espíritus dentro de mí. Uno que me dice deja el trabajo de forma inminente. Otro que dice aguanta, que vas a aprender mucho.”<br>Y terminaba preguntando: ¿me estaré volviendo loca?</div><div>No, Silvia. No te estás volviendo loca.</div><div>Tienes 2 voces. Las tenemos todos.</div><div>El problema es que desde fuera parecen iguales.</div><div>Las 2 hablan. Las 2 tienen argumentos. Y las 2 suenan razonables.</div><div>Pero no son iguales.</div><div>Una habla desde el miedo. Rápido, con urgencia y una con lógica perfecta.</div><div>La otra habla despacio. Sin argumentos. Con una certeza que no necesita defenderse.</div><div>Esa segunda es Ima.</div><div>Y lo que me llama la atención de lo que escribió Silvia es el final. Dice: “en el fondo de mí sé que no es esto lo que quiero.”</div><div>Ahí está.</div><div>No en los 2 espíritus. Sino en ese fondo.</div><div>Ima no grita. No insiste. Pero cuando hay un segundo de silencio real… ya sabe.</div><div>El problema no es distinguir las 2 voces.</div><div>El problema es que nos da miedo escuchar a la que no trae argumentos.</div><div>En tu caso, ¿cuál de las 2 estás escuchando más esta semana?</div><div>Respóndeme. Leo todo.</div><div>Guerra y honor ⚔️<br>Soma</div><div><br></div>", "preheader": "Lo que ha escrito Silvia dentro… y lo que revela."}'::jsonb, '2026-05-01 07:30:49+00'::timestamptz, '{Kit}'::text[], '', 'Al final del mail hay una captura de pantalla con la publicación de Silvia en Skool.', '23790846', '', '', '2026-05-14 10:13:01.104+00'::timestamptz, '2026-04-21 15:09:10.49194+00'::timestamptz, '2026-05-14 10:13:01.11994+00'::timestamptz) ON CONFLICT (id) DO NOTHING;
INSERT INTO piezas (id, idea_id, titulo, formato, columna, contenido, fecha_publicacion, plataformas, url_publicacion, notas, kit_broadcast_id, instagram_media_id, tematica, last_synced_at, created_at, updated_at) VALUES ('790ee62d-0c80-4e63-ae68-1988df408447'::uuid, '5902db80-dd94-4cd8-8a53-afe5e3efcba6'::uuid, 'Los Haters', 'youtube', 'desarrollo', E'{"guion": "<div>TÍTULOS SUGERIDOS (Curiosity &amp; Desire Loops)<br>:<br>El error estratégico que te hace débil (No es tu culpa).<br>Por qué la crítica te destruye (Y cómo ser INMUNE).<br>La mentira de \\"gestionar\\" a los haters.<br><br></div><div>[HOOK — 0:00 – 0:25]<br>No necesitas aprender a gestionar la crítica.<br>(pausa larga)<br>Yo también lo creí.<br>Pensé que el problema era que me afectaba demasiado lo que decía la gente.<br>(pausa)<br>Hasta que entendí algo mucho más incómodo.<br>No me afectaban por lo que decían.<br>Me afectaban porque les había dado autoridad sobre mí.</div><div><br>[PLANTEAMIENTO — 0:25 – 1:30]<br>Nos han vendido que la solución es tener piel dura.<br>Aguantar.<br>Que no te duela.<br>(pausa)<br>No.<br>(pausa)<br>El problema nunca ha sido que te duela.<br>El problema es a quien le has dado permiso para opinar sobre tu vida.<br>(pausa)<br>Porque sin darte cuenta…<br>estás sentando a desconocidos en la mesa donde decides quién eres.</div><div>[BLOQUE 1 — LA MESA — 1:30 – 3:30]<br>Piensa en tu vida como una mesa.<br>(pausa)<br>En esa mesa estás tú.<br>Están tus valores.<br>Tu visión.<br>La gente que respetas de verdad.<br>(pausa)<br>Y entonces haces algo.<br>Subes un vídeo.<br>Lanzas algo.<br>Dices lo que piensas.<br>(pausa)<br>Y aparece alguien.<br>Sin contexto.<br>Sin recorrido.<br>Sin haber construido nada.<br>(pausa)<br>Y tú…<br>(pausa corta)<br>le pones una silla.<br>(pausa larga)<br>Y le dejas opinar sobre tu dirección.<br>(pausa)<br>Ese es el error.<br>No el comentario.<br>El asiento</div><div>[BLOQUE 2 — DOMESTICACIÓN — 3:30 – 5:30]<br>Y esto no pasa de golpe.<br>(pausa)<br>Empieza pequeño.<br>Ajustas un mensaje porque alguien se quejó.<br>Evitas incomodar porque no quieres el ruido.<br>Suavizas una idea que sabes que es tuya.<br>(pausa)<br>Y buscas aprobación.<br>No siempre en voz alta.<br>A veces solo mirando los números.<br>Mirando cuántos han dado like.<br>Esperando que el feed te diga que lo que hiciste estuvo bien.<br>(pausa)<br>Y poco a poco…<br>empiezas a necesitar permiso para avanzar.<br>(pausa)<br>No porque seas débil.<br>Sino porque le has ido cediendo a otros la autoridad que era tuya.<br>(pausa larga)<br>A eso yo lo llamo el hombre domesticado.<br>El que sabe lo que quiere.<br>Y espera que alguien se lo valide antes de ir a por ello.</div><div>[RE-HOOK — 5:30]<br>Y ahora mismo tu cabeza te está diciendo algo.</div><div>[BLOQUE 3 — EL FILTRO — 5:35 – 7:30]<br>\\"Vale, entonces no escucho a nadie.\\"<br>(pausa)<br>No.<br>Esa es la otra trampa.<br>(pausa)<br>La diferencia no está en escuchar o no escuchar.<br>Está en a quién le das asiento en tu mesa.<br>(pausa)<br>Hubo un momento hace años en que recibí una crítica dura.<br>De alguien que no me conocía de nada.<br>Un comentario. Sin contexto. Sin historia detrás.<br>Y me movió.<br>(pausa)<br>Y al mismo tiempo tenía cerca a alguien que había construido durante veinte años.<br>Alguien con cicatrices reales.<br>Que me dijo algo igual de duro.<br>(pausa)<br>Y eso… lo procesé diferente.<br>No porque uno fuera amable y el otro no.<br>Sino porque uno tenía autoridad real y el otro solo tenía conexión a internet.<br>(pausa)<br>Cuando tienes claro quién se sienta en tu mesa…<br>la crítica deja de ser un veredicto.<br>Se convierte en información.<br>Y la información se procesa.<br>Los veredictos te paralizan.<br>(pausa)<br>Hay gente que te puede decir algo que duele…<br>y hay verdad ahí.<br>Y hay gente que habla…<br>y no hay nada.<br>Tu trabajo no es defenderte.<br>Es filtrar.</div><div>[BLOQUE 4 — IDENTIDAD — 7:30 – 9:00]<br>Yo escucho a gente que ha construido.<br>A gente que ha pagado precio de verdad.<br>A gente que tiene cicatrices… y sabe de dónde vienen.<br>(pausa)<br>Pero no negocio mi dirección con espectadores.<br>(pausa)<br>Y esto es lo importante.<br>No porque yo sea mejor que nadie.<br>(pausa)<br>Sino porque es mi vida.<br>Y la autoridad sobre mi vida no está en venta.<br>(pausa)<br>Si alguien tiene algo que decirme que vale la pena escuchar…<br>primero tendrá que ganarse ese asiento.<br>No por currículum.<br>Por coherencia.<br>Por precio pagado.<br>Por haber estado en el mismo fuego.</div><div>[CLÍMAX — 9:00 – 10:00]<br>El problema no es que te critiquen.<br>(pausa)<br>El problema es que has puesto a desconocidos a decidir quién eres.<br>(pausa larga)<br>Y desde ahí…<br>cualquier comentario te mueve.<br>No porque sea verdad.<br>Sino porque no estás firme.<br>(pausa)<br>Y no estás firme porque la raíz de lo que eres…<br>la tienes fuera.<br>En los números.<br>En la aprobación.<br>En el silencio de los que no dijeron nada.<br>(pausa larga)<br>Eso se arregla con una sola cosa.<br>Saber quién eres sin que nadie te lo confirme.</div><div>[CIERRE — 10:00 – 10:45]<br>Grábate esto.<br>(pausa)<br>Tu mesa es sagrada.<br>No todo el mundo se sienta.<br>No todo el mundo opina.<br>No todo el mundo decide.<br>(pausa)<br>Porque cuando todo el mundo tiene voz en tu vida…<br>tú pierdes la tuya.<br>(pausa)<br>Y eso sí que es caro.<br>Mucho más caro que cualquier crítica.</div><div>[CTA — 10:45 – 11:00]<br>Si esto te ha hecho ruido…<br>no respondas aquí.<br>(pausa)<br>Revísate.<br>¿A quién le estás dando asiento que no se lo ha ganado?<br>(pausa)<br>Y si quieres hacer ese trabajo de verdad…<br>lo que construimos en La Hermandad empieza exactamente ahí.<br>El enlace está abajo.<br>(pausa)<br>Guerra y honor ⚔️<br>Soma</div>", "titulo_video": "La mentira de \\"gestionar\\" a los haters."}'::jsonb, NULL, '{YouTube}'::text[], '', 'MINIATURA SUGERIDA
: Un plano tuyo serio, mirando a la cámara, con un texto grande y de alto contraste que diga: "NO LOS ESCUCHES" o "ES UN ERROR". (El texto de la miniatura no debe repetir el título, sino complementarlo para generar un "Visual Stun Gun"
).', '', '', '', NULL, '2026-04-21 20:01:55.142599+00'::timestamptz, '2026-04-21 20:01:55.142599+00'::timestamptz) ON CONFLICT (id) DO NOTHING;
INSERT INTO piezas (id, idea_id, titulo, formato, columna, contenido, fecha_publicacion, plataformas, url_publicacion, notas, kit_broadcast_id, instagram_media_id, tematica, last_synced_at, created_at, updated_at) VALUES ('a7ad9221-07cd-4164-9e83-1084251bcf49'::uuid, 'aea89963-b9c1-41d4-be60-393faf8ba447'::uuid, 'Dios (sin disfraces)', 'youtube', 'desarrollo', E'{"guion": "<div><br></div><div>[HOOK — 0:00 – 0:30]<br>Durante la mayor parte de mi vida…<br>me incomodó usar la palabra Dios.<br>(pausa)<br>No porque no creyera en algo más grande que yo.<br>Sí creía.<br>(pausa)<br>Pero decía \\"el Universo\\".<br>\\"La Fuente\\".<br>\\"La energía\\".<br>Cualquier cosa… menos Dios.<br>(pausa)<br>Y no era casualidad. Durante años me estuve haciendo trampas al solitario con el lenguaje.<br>Hoy te voy a explicar por qué volver a usar la palabra Dios cambió mi forma de operar en el mundo, y por qué el miedo a usarla te está limitando.</div><div>[PLANTEAMIENTO — 0:30 – 1:30]<br>En mi cabeza, Dios era otra cosa.&nbsp;<br>Era religión.<br>Era culpa.<br>Era un sistema de control disfrazado de fe.<br>(pausa)<br>Y yo nunca conecté con eso.<br>Más bien al revés.<br>Todo lo que oliera a imposición… me alejaba.<br>(pausa)<br>Así que durante años…<br>usé eufemismos.<br>Nombres más cómodos.<br>Nombres más \\"seguros\\" para no incomodarme a mí mismo.<br>(pausa)<br>Hasta que entendí que me estaba haciendo trampas con el lenguaje.</div><div>[DESARROLLO — LA PALABRA — 2:30 – 4:30]<br>El problema no es la palabra.<br>(pausa)<br>El problema es todo lo que otros han proyectado sobre ella.<br>Miedo.<br>Dogma.<br>Control.<br>Historias que no son tuyas.<br>(pausa)<br>Y durante años yo rechacé la palabra por eso.<br>(pausa)<br>Pero eso es como dejar de usar el fuego porque hay gente que quema casas.<br>No tiene sentido.<br>(pausa)<br>La palabra no es la institución.<br>La palabra es anterior a cualquier institución.</div><div>[GIRO — 1:30 – 2:30]<br>Hace unos años tuve un período de silencio real.<br>Y cuando digo real, no hablo de meditación programada ni de un retiro espiritual con pulseritas y nombre bonito.<br>Hablo de silencio de verdad. Sin inputs. Sin pantallas. Sin agenda.<br>(pausa)<br>Y en ese silencio apareció algo que llevaba ahí mucho tiempo.<br>(pausa)<br>Una voz.<br>Pero no la voz que piensas.<br>No la que argumenta, que planifica, que tiene miedo.<br>(pausa)<br>Otra.<br>Más profunda.<br>Más antigua.<br>La que ya estaba ahí antes de que el mundo te dijera quién tenías que ser.<br>(pausa)<br>Sócrates lo llamaba el daimonion.<br>La señal interior que solo dice no.<br>Que nunca te dice qué hacer.<br>Que solo aparece cuando estás a punto de traicionarte.<br>(pausa)<br>Los romanos lo llamaban el Genius.<br>La fuerza vital que te animó al nacer.<br>(pausa)<br>Los Indomables lo llamamos Ima.<br>(pausa)<br>Es el nombre que le damos a esa voz más profunda.<br>La que no argumenta.<br>La que no negocia.<br>La que señala.<br>(pausa)<br>Y resulta que eso…<br>es lo que los humanos llevamos llamando Dios desde que tenemos lenguaje.</div><div>[RE-HOOK — 4:30]<br>Y esto cambia algo concreto en cómo vives.<br>Entender esto no es un concepto filosófico abstracto para quedar bien en una cena. Esto cambia algo muy concreto en cómo vives.</div><div>[ESTRUCTURA INVISIBLE — 4:35 – 6:30]<br>Mírame bien. Para mí, Dios no es religión.<br>(pausa)<br>Es operativo.<br>(pausa)<br>Es la voz que escucho cuando no hay ruido.<br>Es el punto desde el que tomo decisiones cuando todo lo externo intenta desviarme.<br>Es la brújula que me alinea cuando me pierdo.<br>(pausa)<br>Pero hay una condición innegociable.<br>(pausa)<br>Esa voz no compite con el ruido.<br>No grita.<br>No insiste.<br>No manda mensajes de voz.<br>(pausa)<br>Solo aparece cuando le dejas espacio.<br>(pausa larga)<br>Y eso lo aprendí de la peor manera posible.<br>Hubo un período en mi vida en el que tenía el calendario lleno. Las notificaciones echando humo. El negocio creciendo a lo bestia. ¿Y sabes qué? No escuchaba nada.<br>No porque no hubiera nada que escuchar.<br>Sino porque el volumen exterior era tan alto que ahogaba todo lo demás.<br>(pausa)<br>Y tomé decisiones desde ahí.<br>Desde el ruido.<br>Desde la urgencia.<br>Desde lo que parecía urgente en lugar de lo que era verdadero.<br>(pausa)<br>Y lo pagué.<br>(pausa)<br>Y lo pagué. Vaya si lo pagué.&nbsp;<br>No  on dinero. Pagué un precio mucho más alto. Lo pagué en dirección.&nbsp;<br>Y lo más grave: lo pagué en lealtad a mí mismo.</div><div>[RE-HOOK — 6:30]<br>Por eso protejo el silencio como protejo cualquier otro recurso escaso.</div><div>[EL SILENCIO COMO CONDICIÓN — 6:35 – 8:00]<br>Porque si no hay silencio…<br>no hay señal.<br>(pausa)<br>Eso no es espiritualidad de aeropuerto.<br>Es física.<br>(pausa)<br>Ima no habla más fuerte cuando la necesitas.<br>Sigue hablando igual.<br>Lo que cambia es si puedes escucharla.<br>(pausa)<br>Y la mayoría de nosotros tenemos el volumen exterior al máximo.<br>Pantalla.<br>Opiniones de otros.<br>Urgencias que no son nuestras.<br>Ruido que llamamos productividad.<br>(pausa)<br>Y desde ahí…<br>es imposible escuchar nada que venga de adentro.<br>(pausa)<br>Por eso protejo mi soledad.<br>Por eso protejo mis mañanas.<br>Por eso hay momentos del día donde no entra nada de fuera.<br>(pausa)<br>No porque sea un monje.<br>Sino porque sé que si no creo ese espacio…<br>voy a tomar decisiones desde el ruido.<br>Y el ruido no tiene interés en mi vida.<br>Yo sí.</div><div>[CONFRONTACIÓN — 8:00 – 9:30]<br>Y aquí viene lo incómodo.<br>(pausa)<br>No creo que la mayoría de la gente no tenga conexión con Dios.<br>(pausa)<br>Creo que no le deja espacio.<br>(pausa)<br>Hay una anestesia muy sofisticada disponible las veinticuatro horas.<br>Contenido.<br>Ruido.<br>Opiniones.<br>Validación externa.<br>La sensación de estar siempre ocupado.<br>(pausa)<br>Y mientras eso esté encendido…<br>Ima no puede hacerse escuchar.<br>(pausa)<br>No porque haya desaparecido.<br>Sigue ahí.<br>Donde siempre ha estado.<br>(pausa)<br>Pero tú no puedes escuchar dos cosas a la vez.<br>Y has elegido, sin elegirlo conscientemente, escuchar el ruido.<br>(pausa)<br>La pregunta no es si crees en algo más grande que tú.<br>La pregunta es si le estás dejando espacio para hablarte.</div><div>[CIERRE — 9:30 – 10:30]<br>(más lento)<br>No te voy a decir en qué creer.<br>(pausa)<br>Te voy a decir algo más sencillo y más difícil.<br>(pausa)<br>Deja de huir de una palabra porque otros la han usado mal.<br>Recalíbrala.<br>Defínela desde dentro.<br>Hazla tuya.<br>(pausa)<br>No la que te enseñaron de pequeño.<br>No la que rechazaste de adolescente.<br>(pausa)<br>La tuya.<br>La que aparece en el silencio.<br>La que señala sin argumentar.<br>La que ya estaba antes de todo lo que te dijeron que eras.<br>(pausa larga)<br>Porque cuando conectas con algo más grande que tú…<br>dejas de construir para el aplauso.<br>(pausa)<br>Y empiezas a construir algo que te trasciende.<br>(pausa)<br>No es religión.<br>(pausa)<br>Es estructura invisible.<br>(pausa final)<br>Es Ima. Es Dios. Llámalo como te dé la gana. Pero haz espacio. Calla el ruido. Y escúchalo.</div><div>[CTA — 10:30 – 11:00]<br>Si esto resonó…<br>probablemente ya sabes de qué te estoy hablando.<br>Ya la has escuchado.<br>Solo que quizás con otro nombre.<br>(pausa)<br>Lo que construimos en La Hermandad empieza exactamente ahí.<br>En aprender a escucharla de verdad.<br>El enlace está abajo.<br>(pausa)<br>Guerra y honor ⚔️<br>Soma</div>", "titulo_video": "Por qué volví a usar la palabra Dios (No es religión)."}'::jsonb, NULL, '{YouTube}'::text[], '', 'TÍTULOS SUGERIDOS (Curiosity & Contrast):
Por qué dejé de decir "El Universo".
El error de la espiritualidad moderna.
Por qué volví a usar la palabra Dios (No es religión).

MINIATURA SUGERIDA: Primer plano tuyo, muy sobrio. Fondo oscuro. Texto en la miniatura: "NO ES RELIGIÓN" o "ME MENTÍA". (Esto crea "disonancia cognitiva", desafiando lo que la gente espera cuando lee la palabra Dios)', '', '', '', NULL, '2026-04-21 21:36:02.415135+00'::timestamptz, '2026-04-21 21:36:02.415135+00'::timestamptz) ON CONFLICT (id) DO NOTHING;
INSERT INTO piezas (id, idea_id, titulo, formato, columna, contenido, fecha_publicacion, plataformas, url_publicacion, notas, kit_broadcast_id, instagram_media_id, tematica, last_synced_at, created_at, updated_at) VALUES ('fa2f9226-6513-4e55-bfb1-2b1bae3e2e29'::uuid, '02faa4c0-d0eb-4974-9eb8-f5e3d2b7622a'::uuid, 'La Certeza como Activo', 'reel', 'desarrollo', '{}'::jsonb, NULL, '{Instagram}'::text[], '', 'Esto sale de la entrevista "Conversaciones sobre Dios" que me hicieron Javi y Blanca.', '', '', '', NULL, '2026-05-12 12:45:02.153405+00'::timestamptz, '2026-05-12 12:45:02.153405+00'::timestamptz) ON CONFLICT (id) DO NOTHING;
INSERT INTO piezas (id, idea_id, titulo, formato, columna, contenido, fecha_publicacion, plataformas, url_publicacion, notas, kit_broadcast_id, instagram_media_id, tematica, last_synced_at, created_at, updated_at) VALUES ('c757fad0-cd4f-4f4a-91bc-f438949f3e2d'::uuid, NULL, 'Backstage | Anillo de Compromiso', 'email', 'agendado', '{"asunto": "No quería buscar el anillo de compromiso", "cuerpo": "No la ayudó.<div>Y por eso ha sido tan potente.</div><div>Esta semana ha pasado algo dentro de La Hermandad que me tiene pensando.</div><div>Ruth compartió que llevaba días removida por dentro. Que había una conversación que sabía que debía tener… y no encontraba el valor.</div><div>No pidió consejo.<br>Ni ayuda.<br>Ni soluciones.</div><div>Simplemente lo soltó.</div><div>Y Laura le respondió.</div><div>Pero no hizo lo típico. No le dijo “yo haría esto”. Ni “tienes que hablar”. Ni “date prioridad”.</div><div>Solo le contó algo que vivió ella.</div><div>En 2009 llevaba 10 años en una relación que ya estaba rota por dentro.</div><div>Y se puso un ultimátum: el día del aniversario, o daban el siguiente paso… o terminaba.</div><div>Así que decidió pedir matrimonio.</div><div>Y empezó a mirar anillos. Y tiendas. Y modelos. Todo eso.</div><div>Pero cuanto más lo pensaba... más le pesaba.</div><div>Hasta que a la semana entendió que no le estaba costando elegir un puto anillo.</div><div>Le estaba costando aceptar que no quería seguir ahí.</div><div>Su cuerpo lo sabía hacía tiempo.<br>Pero la cabeza llevaba años haciendo ruido encima.</div><div>Terminó la relación.</div><div>3 meses después conoció a quien hoy sigue siendo el amor de su vida.<br>10 años después le pidió matrimonio.<br>17 años juntas.</div><div>Y ya.</div><div>Eso fue lo que Laura le respondió a Ruth.</div><div>Sin ir de sabia. Sin dar lecciones. Sin decirle qué tenía que hacer.</div><div>Solo contando su verdad.</div><div>Y estoy pensando en eso.</div><div>En lo poco acostumbrados que estamos a escuchar experiencias sin que venga alguien intentando arreglarnos la vida encima.</div><div>La mayoría de gente no escucha.</div><div>Interpreta.<br>Corrige.<br>Proyecta.<br>Aconseja.</div><div>Muy pocas personas simplemente comparten algo real y te dejan espacio para sacar tus propias conclusiones.</div><div>Y creo que eso tiene muchísimo poder. Así que te dejo una pregunta.</div><div>¿Cuándo fue la última vez que dejaste de intentar parecer el que sabe… y simplemente contaste la verdad de algo que has vivido?</div><div>Respóndeme si te apetece.<br>Leo todo.</div><div>Vive sin correa ⚔️<br>Soma</div><div><br></div><div>​</div><div>​</div><div>​</div><div>​</div><div>​</div><div>​No quiero seguir leyéndote (te doy de baja sin drama) | Actualiza tus preferencias | CG-5, 49, La Massana, AD400</div><div><br></div>", "preheader": "Su cuerpo lo sabía antes que su cabeza. Y eso lo cambió todo"}'::jsonb, '2026-05-15 07:30:00+00'::timestamptz, '{Kit}'::text[], '', '', '24121294', '', '', NULL, '2026-05-14 09:36:41.668502+00'::timestamptz, '2026-05-14 09:37:02.999414+00'::timestamptz) ON CONFLICT (id) DO NOTHING;
INSERT INTO piezas (id, idea_id, titulo, formato, columna, contenido, fecha_publicacion, plataformas, url_publicacion, notas, kit_broadcast_id, instagram_media_id, tematica, last_synced_at, created_at, updated_at) VALUES ('9cd61933-64f0-4bde-b6ce-4002b289006d'::uuid, NULL, 'Autoridad | Promesa mama', 'email', 'agendado', E'{"asunto": "Lo que le prometí a mi madre cuando murió mi padre", "cuerpo": "Mi padre murió cuando yo tenía 19 años.<div>Dejé la universidad primero.<br>Luego dejé los estudios de técnico de sonido.<br>Porque solo quería hacer música.</div><div>Y en una de las conversaciones más duras de mi vida, con mi madre delante preguntándose cómo me iba a ganar la vida y cargando con todo el miedo del mundo sobre mi futuro, le dije:</div><div>\\"Mama no te preocupes. Me haré rico con la música.\\"<br>Ella no me creyó del todo.<br>Yo tampoco sé si me creí a mí mismo.</div><div>Pero la promesa salió de mi boca y se colocó en un sitio del que ya no la podía borrar.</div><div>30 años después, cuando miro hacia atrás y veo los discos de oro y platino, el lanzamiento de un millón de euros y los miles de alumnos formados... lo importante no es la cifra.</div><div>Lo importante es lo que esa promesa hizo conmigo.</div><div>Porque durante todos esos años, esa frase fue una frontera.</div><div>Cuando quería abandonar, estaba ahí.<br>Cuando todo me parecía absurdo, estaba ahí.<br>Cuando no había dinero, ni resultados, ni aplausos, ni garantías… estaba ahí.</div><div>Y esto es algo que la industria del desarrollo personal no entiende. Y nos vende lo contrario.</div><div>Te dice que tu palabra solo cuenta contigo mismo.<br>Que las promesas a los demás son obligaciones tóxicas heredadas.<br>Que la libertad consiste en no deber nada a nadie y \\"amarte primero\\".<br>​<br>​Te están vendiendo el revés del marco.</div><div>Hay promesas que no te encarcelan.<br>Te construyen.</div><div>Una vida sin palabra externa acaba fabricando una palabra interna débil.</div><div>Porque el Hombre Domesticado quiere el compromiso sin los testigos, quiere la ambición sin la deuda y quiere una identidad poderosa sin las consecuencias.</div><div>Pero la soberanía personal no nace en el vacío.</div><div>Nace cuando dices algo que te importa ante alguien que te importa… y luego te pasas años convirtiéndote en el tipo de persona que puede sostenerlo.</div><div>Ahí entrenamos nuestra autoridad.</div><div>No en una afirmación delante del espejo.<br>Ni en una frase bonita escrita en una libreta.<br>Ni en un pico de motivación un domingo por la noche.</div><div>En la promesa que te obliga a crecer aunque nadie te esté mirando.</div><div>Por eso casi nadie tiene una palabra interna fuerte. Una que se crean de verdad.</div><div>Porque llevan años rompiendo contratos invisibles con quienes más les importan... y luego pretenden cumplirse a ellos mismos.</div><div>Imposible. La estructura no aguanta. Claro.</div><div>Así que hoy te propongo que no te preguntes qué quieres conseguir.</div><div>Pregúntate esto.</div><div>¿Qué promesa importante hiciste (a tu madre, a tu padre, a un mentor, a alguien que creyó en ti o incluso a alguien que ya no está) que todavía no has honrado del todo?</div><div>No para castigarte.</div><div>Para recordar quién dijiste que ibas a ser antes de empezar a negociar contigo mismo.</div><div>Vive sin correa ⚔️<br>Soma</div>", "preheader": "No sé si ella me creyó. Pero esa frase me persiguió durante 30 años"}'::jsonb, '2026-05-20 18:00:00+00'::timestamptz, '{Kit}'::text[], '', '', '24121963', '', '', NULL, '2026-05-14 10:12:28.831657+00'::timestamptz, '2026-05-14 10:13:00.743112+00'::timestamptz) ON CONFLICT (id) DO NOTHING;

